import{_ as s,c as a,o as i,b as d}from"./app.1117c437.js";const h='{"title":"\u0413\u043B\u0430\u0432\u0430 8","description":"","frontmatter":{"title":"\u0413\u043B\u0430\u0432\u0430 8","subtitle":"\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0430","tags":"malini","date":"2020-09-20T00:00:00.000Z"},"headers":[],"relativePath":"texts/malini-vijayottara/8/index.md"}',n={},c=d('<div class="stanza"><a href="#s8.1" id="s8.1" class="num">8.1</a><p>(\u0428\u0438\u0432\u0430 \u0441\u043A\u0430\u0437\u0430\u043B):</p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043F\u043E\u0432\u0435\u0434\u0430\u044E \u043E \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u0438, \u0434\u0430\u044E\u0449\u0435\u043C (\u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u0435) \u0432\u0441\u0435\u0445 \u0436\u0435\u043B\u0430\u043D\u0438\u0439, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044E \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E (\u0441\u0430\u0434\u0445\u0430\u043A\u0430) \u0441\u0442\u0430\u043D\u0435\u0442 \u0440\u0430\u0432\u043D\u044B\u043C \u0439\u043E\u0433\u0438\u043D\u0438 .</p></div><div class="stanza"><a href="#s8.2" id="s8.2" class="num">8.2</a><p>\u0412\u043D\u0430\u0447\u0430\u043B\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0434\u0433\u043E\u0442\u043E\u0432\u0438\u0442\u044C \u043C\u0435\u0441\u0442\u043E \u0434\u043B\u044F \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u044F \u0432 \u0447\u0438\u0441\u0442\u043E\u0439 \u043C\u0435\u0441\u0442\u043D\u043E\u0441\u0442\u0438, \u0440\u0430\u0434\u0443\u044E\u0449\u0435\u0439 \u0443\u043C, \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u043A\u0440\u0443\u0433\u043B\u043E\u0439 \u043E\u0433\u043D\u0435\u043D\u043D\u043E\u0439 \u044F\u043C\u043E\u0439;</p></div><div class="stanza"><a href="#s8.3" id="s8.3" class="num">8.3</a><p>\u0414\u043B\u044F \u043F\u043E\u0447\u0438\u0442\u0430\u043D\u0438\u044F, \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0435 \u043D\u0430 25 \u0440\u0430\u0432\u043D\u044B\u0445 \u0447\u0430\u0441\u0442\u0435\u0439 \u0441 \u0446\u0435\u043D\u0442\u0440\u0430\u043B\u044C\u043D\u043E\u0439 \u0447\u0430\u0441\u0442\u044C\u044E, \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u043D\u043E\u0439 \u0441\u043E \u0432\u0441\u0435\u0445 \u0441\u0442\u043E\u0440\u043E\u043D \u0447\u0435\u0442\u044B\u0440\u0435\u0445\u0443\u0433\u043E\u043B\u044C\u043D\u043E\u0439 \u043E\u0433\u0440\u0430\u0434\u043E\u0439, \u0443\u043A\u0440\u0430\u0448\u0435\u043D\u043D\u043E\u0439 \u043F\u0430\u0440\u0432\u0430\u0443\u0448\u0442\u0445\u0435\u043D\u043E\u0439 (\u0442.\u0435. \u043F\u0435\u0440\u0435\u0434\u043D\u0435\u0439 \u0447\u0430\u0441\u0442\u044C\u044E \u0430\u0433\u043D\u0438\u043A\u0443\u043D\u0434\u044B) .</p></div><div class="stanza"><a href="#s8.4-6" id="s8.4-6" class="num">8.4-6</a><p>\u0417\u0430\u0442\u0435\u043C \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u0442\u0441\u044F \u043E\u043C\u043E\u0432\u0435\u043D\u0438\u0435. \u041F\u043E\u0431\u0435\u0436\u0434\u0430\u044F \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u043E\u043C\u043E\u0432\u0435\u043D\u0438\u0435\u043C \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u0430\u043C\u0438, \u0437\u043D\u0430\u044E\u0449\u0438\u0439 \u043C\u0430\u043D\u0442\u0440\u0443 \u043F\u0443\u0441\u0442\u044C \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u0442 \u0435\u0433\u043E \u0448\u0435\u0441\u0442\u044C \u0432\u0438\u0434\u043E\u0432, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u043E\u043C\u043E\u0432\u0435\u043D\u0438\u044F \u0432 \u043F\u0435\u043F\u043B\u0435. \u041E\u043C\u044B\u0432\u0430\u044F\u0441\u044C \u043E\u0442 \u0433\u0440\u044F\u0437\u0438 \u043F\u0440\u0438 \u043E\u043C\u043E\u0432\u0435\u043D\u0438\u0438 \u043F\u0435\u043F\u043B\u043E\u043C, \u0437\u0430\u0433\u043E\u0432\u043E\u0440\u0435\u043D\u043D\u044B\u043C \u0441\u0435\u043C\u044C \u0440\u0430\u0437 \u0432\u0435\u043B\u0438\u043A\u043E\u0439 \u0430\u0441\u0442\u0440\u0430 (\u0431\u0438\u0434\u0436\u0435\u0439) \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043D\u0430\u0442\u0435\u0440\u0435\u0442\u044C (\u0438\u043C) \u0442\u0435\u043B\u043E \u0432 \u043E\u0431\u0440\u0430\u0442\u043D\u043E\u043C \u043F\u043E\u0440\u044F\u0434\u043A\u0435 (<em>\u0441 \u0433\u043E\u043B\u043E\u0432\u044B \u0434\u043E \u043D\u043E\u0433</em>). \u0417\u0430\u0442\u0435\u043C \u0432\u043D\u0430\u0447\u0430\u043B\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043A\u0440\u044B\u0442\u044C \u0433\u043E\u043B\u043E\u0432\u0443 5 \u0447\u043B\u0435\u043D\u043D\u044B\u043C\u0438 \u0432\u0438\u0434\u044C\u044F\u043C\u0438. (\u0417\u0430\u0442\u0435\u043C) \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u0442\u0441\u044F \u043E\u043C\u043E\u0432\u0435\u043D\u0438\u0435 (\u0432\u043E\u0434\u043E\u0439) \u0441 \u0448\u0435\u0441\u0442\u0438\u0447\u043B\u0435\u043D\u043D\u043E\u0439 \u043C\u0443\u043B\u0430 \u043C\u0430\u043D\u0442\u0440\u043E\u0439 .</p></div><div class="stanza"><a href="#s8.7" id="s8.7" class="num">8.7</a><p>\u0417\u0430\u0442\u0435\u043C \u0432 \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u043E\u0439 \u043E\u0434\u0435\u0436\u0434\u0435 \u0438\u043B\u0438 \u0431\u0435\u0437 \u043E\u0434\u0435\u0436\u0434\u044B, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0447\u0438\u0441\u0442\u0438\u0442\u044C \u0440\u0443\u043A\u0438 \u0438 \u0441\u0442\u043E\u043F\u044B. \u0421\u043E\u0432\u0435\u0440\u0448\u0438\u0432 \u0430\u0447\u0430\u043C\u0430\u043D\u0443, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u043C\u0430\u0440\u0434\u0436\u0430\u043D\u0443 (\u043A\u0440\u043E\u043F\u043B\u0435\u043D\u0438\u0435), \u0441 \u0432\u0438\u0434\u044C\u0435\u0439 \u0438 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E\u043C \u0432\u0430\u0440\u043D .</p></div><div class="stanza"><a href="#s8.8" id="s8.8" class="num">8.8</a><p>\u0412\u044B\u043F\u043E\u043B\u043D\u0438\u0432 \u043D\u044C\u044F\u0441\u0443, \u0437\u0430\u0442\u0435\u043C (\u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u0442\u0441\u044F) \u043E\u0431\u0449\u0430\u044F \u0430\u0433\u0445\u0430\u043C\u0430\u0440\u0448\u0430\u043D\u0430, (\u0437\u0430\u0442\u0435\u043C) \u0443\u043F\u0430\u0441\u0442\u0445\u0430\u043D\u0430, (\u0437\u0430\u0442\u0435\u043C) \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0442\u0438 \u043D\u0430 \u0447\u0435\u0442\u043A\u0430\u0445 \u043E\u0434\u043D\u043E\u0441\u043B\u043E\u0436\u043D\u0443\u044E (\u043C\u0430\u043D\u0442\u0440\u0443) .</p></div><div class="stanza"><a href="#s8.8-9" id="s8.8-9" class="num">8.8-9</a><p>\u041F\u0440\u0438 \u043E\u043C\u043E\u0432\u0435\u043D\u0438\u0438 \u0432\u043E\u0434\u043E\u0439 \u0438 \u0433\u043B\u0438\u043D\u043E\u0439, \u0437\u0430\u0433\u043E\u0432\u043E\u0440\u0435\u043D\u043D\u043E\u0439 7 \u0440\u0430\u0437 \u0430\u0441\u0442\u0440\u0430 (\u0431\u0438\u0434\u0436\u0435\u0439), \u0436\u0435\u0440\u0442\u0432\u0443\u044F, \u043A\u0430\u043A \u0438 \u0440\u0430\u043D\u0435\u0435 (\u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435) \u0442\u0435\u043B\u043E, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0432\u0435\u0440\u0448\u0438\u0442\u044C \u043E\u043C\u043E\u0432\u0435\u043D\u0438\u0435 \u0434\u043B\u044F (\u043E\u0447\u0438\u0449\u0435\u043D\u0438\u044F) \u043E\u0442 \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u044F .</p></div><div class="stanza"><a href="#s8.10-12" id="s8.10-12" class="num">8.10-12</a><p>\u041A\u0430\u043A \u0438 \u0440\u0430\u043D\u0435\u0435, \u044D\u0442\u043E \u043E\u043C\u043E\u0432\u0435\u043D\u0438\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u0442\u0441\u044F \u0441 \u0432\u043E\u0434\u043E\u0439, \u043A\u0430\u043A \u043F\u043E\u0434\u043E\u0431\u0430\u0435\u0442. \u041E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E \u043E\u043C\u044B\u0432\u0430\u044F\u0441\u044C \u0438 \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F \u0442\u0440\u0438\u0436\u0434\u044B \u0432\u0438\u0434\u044C\u044F (\u043C\u0430\u043D\u0442\u0440\u0443) \u043F\u0443\u0441\u0442\u044C \u0437\u043D\u0430\u044E\u0449\u0438\u0439 \u043C\u0430\u043D\u0442\u0440\u0443 \u0432\u044B\u043B\u044C\u0435\u0442 \u0441\u0435\u0431\u0435 \u043D\u0430 \u0433\u043E\u043B\u043E\u0432\u0443 \u0432\u043E\u0434\u0443, \u0441 \u043E\u043C\u044B\u0432\u0430\u044E\u0449\u0435\u0439 \u043C\u0430\u043D\u0442\u0440\u043E\u0439. \u041F\u0443\u0441\u0442\u044C \u0441\u043E\u0432\u0435\u0440\u0448\u0438\u0442 \u0442\u0430\u043A \u0436\u0435 \u043E\u043C\u043E\u0432\u0435\u043D\u0438\u0435 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E\u043C, \u043D\u0430\u0432\u043E\u0437\u043E\u043C, \u0432\u0435\u0442\u0440\u043E\u043C. \u041F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F \u0432\u0435\u043B\u0438\u043A\u0443\u044E \u0430\u0441\u0442\u0440\u0430 (\u0431\u0438\u0434\u0436\u0443), \u043F\u0443\u0441\u0442\u044C \u043F\u0440\u043E\u0439\u0434\u0435\u0442, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F 7 \u0448\u0430\u0433\u043E\u0432. \u041F\u0443\u0441\u0442\u044C \u0441\u043D\u043E\u0432\u0430 \u043F\u0440\u043E\u0439\u0434\u0435\u0442, \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u044F \u043D\u0430\u0434 \u043F\u0430\u0440\u0430\u043F\u0430\u0440\u0430 (\u0432\u0438\u0434\u044C\u0435\u0439) .</p></div><div class="stanza"><a href="#s8.13" id="s8.13" class="num">8.13</a><p>\u042D\u0442\u043E\u0442 (\u043F\u0443\u0442\u044C) \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F \u0440\u0430\u0432\u043D\u044B\u043C \u0433\u043E\u0434\u0443 \u0442\u0430\u043F\u0430\u0441\u0430, \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0439\u043E\u0433\u0438. \u041F\u0443\u0441\u0442\u044C \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F\u0449\u0438\u0439 \u043C\u0430\u043D\u0442\u0440\u0443 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442 (\u0443\u0440\u043E\u0432\u0435\u043D\u044C) \u043F\u0430\u0440\u0430, \u043A\u0430\u043A \u043F\u043E\u0442\u043E\u043A \u0430\u043C\u0440\u0438\u0442\u044B .</p></div><div class="stanza"><a href="#s8.14" id="s8.14" class="num">8.14</a><p>\u041F\u043E\u0434\u043D\u0438\u043C\u0430\u044F \u043E\u0433\u043E\u043D\u044C \u043E\u0442 \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u0438\u044F \u0431\u043E\u043B\u044C\u0448\u0438\u0445 \u043F\u0430\u043B\u044C\u0446\u0435\u0432 (\u0441\u0442\u043E\u043F) \u043F\u0443\u0441\u0442\u044C \u043E\u043D \u0441\u043E\u0436\u0436\u0435\u0442 (\u0441\u0432\u043E\u0435 \u0442\u0435\u043B\u043E) \u0430\u0441\u0442\u0440\u0430 (\u0431\u0438\u0434\u0436\u0435\u0439). \u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u043C\u044B\u0442\u044C \u0441\u0432\u043E\u0435 \u0442\u0435\u043B\u043E \u0430\u043C\u0440\u0438\u0442\u043E\u0439 \u043F\u0430\u0440\u0430 .</p></div><div class="stanza"><a href="#s8.15" id="s8.15" class="num">8.15</a><p>\u041F\u043E\u0434\u043D\u0435\u0441\u044F \u043C\u0430\u043D\u0442\u0440\u0443 \u0441\u043E\u043B\u043D\u0446\u0443 \u0438 \u0434\u0440\u0443\u0433\u0438\u043C (\u0431\u043E\u0433\u0430\u043C), \u043F\u0430\u043C\u044F\u0442\u0443\u044F \u0430\u0441\u0442\u0440\u0430 (\u0431\u0438\u0434\u0436\u0443), \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0442\u043F\u0440\u0430\u0432\u0438\u0442\u0441\u044F \u0432 \u043C\u0435\u0441\u0442\u043E \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u044F, \u043E\u0447\u0438\u0449\u0435\u043D\u043D\u043E\u0435 \u0430\u0441\u0442\u0440\u0430 (\u0431\u0438\u0434\u0436\u0435\u0439). \u041F\u0443\u0441\u0442\u044C \u043E\u043D \u0432\u043E\u0439\u0434\u0435\u0442 (\u0442\u0443\u0434\u0430) \u0447\u0438\u0441\u0442\u044B\u043C \u0438 \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u044B\u043C .</p></div><div class="stanza"><a href="#s8.16" id="s8.16" class="num">8.16</a><p>\u041F\u043E\u0447\u0442\u0438\u0432 \u0442\u0430\u043C \u0434\u043B\u044F \u0443\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u043F\u0440\u0435\u043F\u044F\u0442\u0441\u0442\u0432\u0438\u0439, \u043F\u043E\u043A\u0440\u043E\u0432\u0438\u0442\u0435\u043B\u0435\u0439 \u0432\u0440\u0430\u0442, \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F \u0430\u0441\u0442\u0440\u0430 (\u0431\u0438\u0434\u0436\u0443) \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442\u044C (\u0442\u0443\u0434\u0430) \u0446\u0432\u0435\u0442\u044B, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u043E\u0433\u043E\u043D\u044C. \u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u043E\u0439\u0442\u0438 \u0432 \u043C\u0435\u0441\u0442\u043E \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u044F, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u043E\u0433\u043D\u044E \u0438 \u0434\u0435\u0440\u0436\u0430 \u043E\u0433\u043E\u043D\u044C .</p></div><div class="stanza"><a href="#s8.17-20" id="s8.17-20" class="num">8.17-20</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u043E\u0433\u0440\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u0434\u0435\u0441\u044F\u0442\u0438 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0439 \u0430\u0441\u0442\u0440\u0430 (\u0431\u0438\u0434\u0436\u0435\u0439). \u0412\u043E\u0439\u0434\u044F \u0441 \u0432\u043E\u0441\u0442\u043E\u043A\u0430 \u0438\u043B\u0438 \u0441 \u043B\u0443\u043D\u043D\u043E\u0433\u043E \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F (<em>\u0441 \u0441\u0435\u0432\u0435\u0440\u0430</em>) \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0438\u0441\u0442\u0443\u043F\u0438\u0442\u044C (\u043A \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044E) \u043D\u044C\u044F\u0441\u044B \u0441 \u0430\u0441\u0442\u0440\u0430 \u043C\u0430\u043D\u0442\u0440\u043E\u0439 \u0438 \u043E\u0433\u043D\u0435\u043C \u0432\u0435\u0447\u043D\u043E\u0441\u0442\u0438 (\u043A\u0430\u043B\u0430\u043D\u0430\u043B\u0430). \u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0431\u043E\u043B\u044C\u0448\u0438\u0445 \u043F\u0430\u043B\u044C\u0446\u0435\u0432 \u043D\u043E\u0433, \u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u044E\u0449\u0435\u0435\u0441\u044F \u0432 \u043F\u0435\u043F\u0435\u043B \u0442\u0435\u043B\u043E \u043E\u0431\u043B\u0430\u0447\u0435\u043D\u043D\u043E\u0435 \u0432 \u0431\u0440\u043E\u043D\u044E \u0432\u0435\u0442\u0440\u0430. \u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u0435\u0431\u044F \u0435\u0434\u0438\u043D\u044B\u043C \u0441 \u0428\u0438\u0432\u043E\u0439 \u0438 \u0431\u0438\u043D\u0434\u0443. \u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0435\u0434\u0438\u043D\u0438\u0442\u044C\u0441\u044F \u0441 \u0415\u0433\u043E \u0428\u0430\u043A\u0442\u0438. \xAB\u041E\u043D\u0430 \u0435\u0441\u0442\u044C \u042F\xBB (\u0421\u0410\u2019\u0425\u0410\u041C) \u0435\u0441\u0442\u044C \u043D\u0435\u043F\u043E\u0431\u0435\u0434\u0438\u043C\u0430\u044F \u043C\u0430\u043D\u0442\u0440\u0430 .</p></div><div class="stanza"><a href="#s8.21-23" id="s8.21-23" class="num">8.21-23</a><p>\u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0434\u043E\u0431\u0430\u0432\u0438\u0442\u044C \u043A \u044D\u0442\u043E\u0439 \u043C\u0430\u043D\u0442\u0440\u0435, \u043E\u0431\u0440\u0430\u0437\u0443 \u0412\u0438\u0434\u044C\u0438, \u043E \u0428\u0430\u043D\u043A\u0430\u0440\u0438, \xAB\u0448\u0430\u0433 \u043F\u0430\u043B\u043A\u0438\xBB, \xAB\u0432\u0435\u043B\u0438\u043A\u0443\u044E \u043F\u0440\u0430\u043D\u0443\xBB, \xAB\u0432\u044B\u0440\u043E\u0441\u0448\u0443\u044E \u043F\u0430\u043B\u043A\u0443\xBB, \u0441 \xAB\u043F\u0443\u043F\u043E\u043C\xBB \u0438 \xAB\u044F\u0433\u043E\u0434\u0438\u0446\u0430\u043C\u0438\xBB. \u041F\u043E\u0441\u043B\u0435 \u043D\u0438\u0445 - \xAB\u043B\u0435\u0432\u0443\u044E \u0433\u0440\u0443\u0434\u044C\xBB, \u043F\u043E\u0441\u043B\u0435 \u043D\u0435\u0435 - \xAB\u0433\u043E\u0440\u043B\u043E\xBB, \xAB\u043B\u0435\u0432\u0443\u044E \u0432\u0435\u0440\u0448\u0438\u043D\u0443\xBB, \u0443\u043A\u0440\u0430\u0448\u0435\u043D\u043D\u0443\u044E \xAB\u043B\u0435\u0432\u043E\u0439 \u043C\u0443\u0434\u0440\u043E\u0439\xBB, \u0431\u0438\u043D\u0434\u0443, \u043F\u043E\u043B\u0443\u043C\u0435\u0441\u044F\u0446, \u043D\u0435\u0431\u043E \u0443\u043A\u0440\u0430\u0448\u0435\u043D\u043D\u043E\u0435 \u043D\u0430\u0434\u043E\u0439, \u0448\u0430\u043A\u0442\u0438 \u0438 \u0431\u0438\u043D\u0434\u0443. \u042D\u0442\u043E \u043B\u0443\u0447\u0448\u0430\u044F \u043F\u0438\u043D\u0434\u0430 (\u043C\u0430\u043D\u0442\u0440\u0430), \u043E \u0414\u0435\u0432\u0438 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0434\u0435\u0432\u044F\u0442\u0438\u0441\u043B\u043E\u0436\u043D\u043E\u0439.(<em>\u043F\u043E \u0432\u0441\u0435\u0439 \u0432\u0438\u0434\u0438\u043C\u043E\u0441\u0442\u0438 \u0438\u043C\u0435\u0435\u0442\u0441\u044F \u0432 \u0432\u0438\u0434\u0443 \u043D\u0430\u0432\u0430\u0442\u043C\u0430 \u043C\u0430\u043D\u0442\u0440\u0430</em>: \u0425 \u0420 \u041A\u0428 \u041C \u041B \u0412 \u0419 \u041D \u0423\u041C)</p></div><div class="stanza"><a href="#s8.23-26" id="s8.23-26" class="num">8.23-26</a><p>\u0422\u0432\u043E\u0440\u044F\u0449\u0430\u044F \u0432\u0441\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430, \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0438\u043C\u0430\u044F \u0432\u0442\u0430\u0439\u043D\u0435. \u041D\u0438\u0436\u0435 \u044D\u0442\u043E\u0439 \u0442\u0440\u0435\u0449\u0430\u0449\u0435\u0439 \u043C\u0430\u043D\u0442\u0440\u044B \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443 \u0448\u0430\u0434\u0430\u043D\u0433\u0430 (\u041D\u044C\u044F\u0441\u0443), \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0441\u0435\u0440\u0434\u0446\u0430 \u0441 \u0448\u0435\u0441\u0442\u044C\u044E \u0434\u043E\u043B\u0433\u0438\u043C\u0438 \u0433\u043B\u0430\u0441\u043D\u044B\u043C\u0438. \u0412 \u043D\u0430\u0447\u0430\u043B\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0442\u044C \xAB\u0443\u0441\u0442\u0430\xBB, \u0441 \u0431\u0438\u0434\u0436\u0430\u043C\u0438: \u041A\u0428\u0410, \u0420\u0410, \u0412\u0410, \u041B\u0410, \u0443\u043A\u0440\u0430\u0448\u0435\u043D\u043D\u044B\u043C\u0438 \u0441\u0438\u044F\u044E\u0449\u0438\u043C\u0438 \u0431\u0438\u043D\u0434\u0443. \u041D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0443\u0441\u0442 \u0438 (\u0434\u0430\u043B\u0435\u0435 \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443). \u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0432 \u043A\u0430\u0436\u0434\u043E\u0439 \u0447\u0430\u0441\u0442\u0438 \u0442\u0435\u043B\u0430 \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441\u043E \u043B\u0431\u0430:</p></div><div class="stanza"><a href="#s8.24-27" id="s8.24-27" class="num">8.24-27</a><p>(\u0413\u043B\u0430\u0441\u043D\u0430\u044F) \u0410 (\u0440\u0430\u0437\u043C\u0435\u0449\u0430\u0435\u0442\u0441\u044F) \u043D\u0430 \u043B\u0431\u0443, \u043D\u0430 \u0440\u043E\u0442 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0432\u0442\u043E\u0440\u0443\u044E (\u0433\u043B\u0430\u0441\u043D\u0443\u044E \u0410\u0410). \u041D\u0430 \u0433\u043B\u0430\u0437\u0430 - \u0418 \u0438 \u0418\u0418. \u041D\u0430 \u043E\u0431\u0430 \u0443\u0445\u0430 \u0423 \u0438 \u0423\u0423. \u041D\u0430 \u043D\u043E\u0437\u0434\u0440\u0438 - \u0420 \u0438 \u0420\u0420, \u043D\u0430 \u0449\u0435\u043A\u0438 - \u041B \u0438 \u041B\u0420. \u041D\u0430 \u0432\u0435\u0440\u0445\u043D\u0438\u0435 \u0438 \u043D\u0438\u0436\u043D\u0438\u0435 \u0437\u0443\u0431\u044B (\u043F\u043E\u043C\u0435\u0449\u0430\u044E\u0442\u0441\u044F) \u042D \u0438 \u0410\u0419. \u0421\u043B\u043E\u0433\u0438 \u041E \u0438 \u0410\u0423 - \u043D\u0430 \u0433\u0443\u0431\u044B .</p></div><div class="stanza"><a href="#s8.29-30" id="s8.29-30" class="num">8.29-30</a><p>\u041D\u0430 \u043C\u0430\u043A\u0443\u0448\u043A\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0442\u044C (\u0430\u043D\u0443\u0441\u0432\u0430\u0440\u0443) \u0410\u041C, \u0432\u0438\u0441\u0430\u0440\u0433\u0443 - \u043D\u0430 \u044F\u0437\u044B\u043A\u0435, \u043D\u0430 \u043F\u0440\u0430\u0432\u0443\u044E \u0434\u0435\u043B\u044C\u0442\u0443, \u043F\u043B\u0435\u0447\u043E, \u043F\u0440\u0435\u0434\u043F\u043B\u0435\u0447\u044C\u0435, \u043A\u0438\u0441\u0442\u044C \u0438 \u043D\u043E\u0433\u043E\u0442\u044C \u0431\u043E\u043B\u044C\u0448\u0435\u0433\u043E \u043F\u0430\u043B\u044C\u0446\u0430 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u041A\u0410- \u0432\u0430\u0440\u0433\u0443. \u0421\u043B\u0435\u0432\u0430 (\u043D\u0430 \u043B\u0435\u0432\u0443\u044E \u0440\u0443\u043A\u0443 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442\u044C) \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443 (\u0427\u0410 \u0412\u0430\u0440\u0433\u0443) \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0427\u0410. \u0414\u0432\u0435 \u0412\u0430\u0440\u0433\u0438 \u043D\u0430\u0447\u0438\u043D\u0430\u044E\u0449\u0438\u0445\u0441\u044F \u0441 \u0422\u0410 \u0422\u0410 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u044F\u0433\u043E\u0434\u0438\u0446 .</p></div><div class="stanza"><a href="#s8.31" id="s8.31" class="num">8.31</a><p>\u041D\u0430 \u0441\u0442\u043E\u043F\u044B, \u043D\u0430 \u043E\u0431\u0430 \u0431\u043E\u043A\u0430, \u043D\u0430 \u0441\u043F\u0438\u043D\u0443, \u043D\u0430 \u0436\u0438\u0432\u043E\u0442 \u0438 \u0441\u0435\u0440\u0434\u0446\u0435 \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443, \u043D\u0430 \u043B\u0438\u043D\u0438\u044E \u043A\u043E\u0436\u0438, \u043A\u0440\u043E\u0432\u0438, \u043C\u044F\u0441\u0430, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0419\u0410- \u0432\u0430\u0440\u0433\u0443 .</p></div><div class="stanza"><a href="#s8.32" id="s8.32" class="num">8.32</a><p>(\u041F\u043E\u043B\u0443\u0433\u043B\u0430\u0441\u043D\u044B\u0435), \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0428\u0410 \u043F\u043E\u043C\u0435\u0449\u0430\u044E\u0442\u0441\u044F \u0432 \u043F\u044F\u0442\u0435\u0440\u043A\u0443: \u043A\u043E\u0441\u0442\u0438, \u0436\u0438\u0440, \u0441\u0435\u043C\u044F, \u043F\u0440\u0430\u043D\u0430, \u0438 \u043E\u0442\u0432\u0435\u0440\u0441\u0442\u0438\u044F (\u0442\u0435\u043B\u0430). \u0420\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0432 \u0447\u0430\u0441\u0442\u0438 \u0442\u0435\u043B\u0430 \u043C\u0443\u0440\u0442\u0438, \u043F\u0443\u0441\u0442\u044C \u043C\u0443\u0434\u0440\u044B\u0439 \u043F\u0440\u0438\u0437\u043E\u0432\u0435\u0442 \u0428\u0438\u0432\u0443 .</p></div><div class="stanza"><a href="#s8.33-34" id="s8.33-34" class="num">8.33-34</a><p>\u041D\u0430\u0434 \xAB\u043F\u0440\u0430\u043D\u043E\u0439\xBB \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442\u044C \xAB\u043F\u0443\u043F\xBB, \u0441\u0432\u0435\u0440\u0445\u0443 \u043D\u0435\u0433\u043E - \xAB\u043F\u0440\u0430\u0432\u044B\u0439 \u0431\u043E\u043B\u044C\u0448\u043E\u0439 \u043F\u0430\u043B\u0435\u0446\xBB, \xAB\u043B\u0435\u0432\u043E\u0435 \u0443\u0445\u043E\xBB - \u044D\u0442\u043E \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u044B\u0439, \u0434\u0430\u044E\u0449\u0438\u0439 \u0432\u0441\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430 \u0428\u0438\u0432\u0430. \u042D\u0442\u043E - \u0412\u0435\u043B\u0438\u043A\u0430\u044F \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0411\u0445\u0430\u0439\u0440\u0430\u0432\u044B, \u0412\u0435\u043B\u0438\u043A\u043E\u0433\u043E \u0414\u0443\u0445\u0430. \u041F\u0440\u0438 \u043F\u043E\u043C\u043E\u0449\u0438 \u044D\u0442\u043E\u0439 (\u043C\u0430\u043D\u0442\u0440\u044B) \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u044E\u0442\u0441\u044F \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F \u043D\u0430\u0434 \u0447\u0430\u0441\u0442\u044F\u043C\u0438 \u0442\u0435\u043B\u0430 \u043A\u0430\u043A (\u0431\u044B\u043B\u043E \u043E\u043F\u0438\u0441\u0430\u043D\u043E) \u0440\u0430\u043D\u0435\u0435 \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435\u043C \u0433\u043B\u0430\u0441\u043D\u044B\u0445 .</p></div><div class="stanza"><a href="#s8.35" id="s8.35" class="num">8.35</a><p>\u041C\u0443\u0440\u0442\u0438 \u043D\u044C\u044F\u0441\u0430 (<em>\u043D\u044C\u044F\u0441\u0430 \u043D\u0430\u0432\u0430\u0442\u043C\u0430\u043C\u0430\u043D\u0442\u0440\u044B \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0430\u043D\u0433\u0430 \u043D\u044C\u044F\u0441\u043E\u0439</em>), \u0441\u0440\u0438\u0448\u0442\u0438 \u043D\u044C\u044F\u0441\u0430 (<em>\u043C\u0430\u0442\u0440\u0438\u043A\u0430 \u043D\u044C\u044F\u0441\u0430</em>)<em>,</em> \u0442\u0440\u0438 \u0442\u0430\u0442\u0442\u0432\u0430 \u043D\u044C\u044F\u0441\u0430 (<em>\u043D\u044C\u044F\u0441\u0430 \u0428\u0438\u0432\u0430 \u0442\u0430\u0442\u0442\u0432\u044B, \u0412\u0438\u0434\u044C\u0438, \u0438 \u0410\u0442\u043C\u044B</em>) \u043D\u044C\u044F\u0441\u0430 \u0432\u043E\u0441\u044C\u043C\u0438 \u0447\u0430\u0441\u0442\u0435\u0439 \u043C\u0443\u0440\u0442\u0438, \u0428\u0438\u0432\u0430 \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0430\u043D\u0433\u0430\u043C\u0438 - \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0448\u0435\u0441\u0442\u0438\u0447\u0430\u0441\u0442\u043D\u0430\u044F \u0428\u0438\u0432\u0430 \u041D\u044C\u044F\u0441\u0430 .</p></div><div class="stanza"><a href="#s8.36-38" id="s8.36-38" class="num">8.36-38</a><p>\u041F\u043E\u0441\u043B\u0435 \u043D\u0435\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u0448\u0430\u043A\u0442\u0430 \u043D\u044C\u044F\u0441\u0443. \u0421\u043B\u0443\u0448\u0430\u0439, \u043A\u0430\u043A (\u044D\u0442\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u0434\u0435\u043B\u0430\u0442\u044C). \u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0432 \u041C\u0443\u0440\u0442\u0438 \u043F\u0430\u0440\u0430\u043F\u0430\u0440\u0430 (\u043C\u0430\u043D\u0442\u0440\u0443) \u0438 \u0435\u0435 \xAB\u0443\u0441\u0442\u0430\xBB, (\u0437\u0430\u0442\u0435\u043C) \u043C\u0430\u043B\u0438\u043D\u0438. \u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 (\u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0442\u044C) \u041D\u044C\u044F\u0441\u0443 \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u043F\u0430\u0440\u0430 \u0432 \u0442\u0440\u0435\u0445 (\u043C\u0435\u0441\u0442\u0430\u0445): \u043C\u0430\u043A\u0443\u0448\u043A\u0435, \u0441\u0435\u0440\u0434\u0446\u0435 \u0438 \u0441\u0442\u043E\u043F\u0430\u0445. \u0412\u043E\u0441\u044C\u043C\u0435\u0440\u043A\u0443 \u0432\u0438\u0434\u0438\u0439, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0410\u0433\u0445\u043E\u0440\u0438 \u0438 \u0432\u0438\u0434\u044C\u044F\u043D\u0433\u0443 \u043A\u0430\u043A \u0438 \u0440\u0430\u043D\u0435\u0435 (\u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0442\u044C) \u043D\u0430 \u043C\u0430\u043A\u0443\u0448\u043A\u0443, \u0440\u043E\u0442 \u0433\u043E\u0440\u043B\u043E, \u0441\u0435\u0440\u0434\u0446\u0435, \u043F\u0443\u043F\u043E\u043A, \xAB\u0442\u0430\u0439\u043D\u043E\u0435 \u043C\u0435\u0441\u0442\u043E\xBB, \u0431\u0435\u0434\u0440\u0430 \u0438 \u0441\u0442\u043E\u043F\u044B. \u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0438\u0437\u0432\u0430\u0442\u044C \u0428\u0430\u043A\u0442\u0438, \u043F\u043E\u0447\u0438\u0442\u0430\u0435\u043C\u0443\u044E \u0432\u0441\u0435\u043C\u0438 \u0439\u043E\u0433\u0438\u043D\u0430\u043C\u0438 .</p></div><div class="stanza"><a href="#s8.39" id="s8.39" class="num">8.39</a><p>\u0414\u0436\u0438\u0432\u0430 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0430\u044F \u043F\u043E\u0441\u0440\u0435\u0434\u0438 \u043E\u0433\u0440\u0430\u0436\u0434\u0435\u043D\u0438\u044F, \u0441\u0438\u044F\u044E\u0449\u0430\u044F, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u043E\u0433\u043D\u044E \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0435\u043D\u0438\u044F, \u041F\u0440\u0435\u0441\u0432\u0435\u0442\u043B\u0430\u044F, \u0441 \u0443\u043A\u0440\u0430\u0448\u0435\u043D\u043D\u043E\u0439 \u043B\u0435\u0432\u043E\u0439 \u043D\u043E\u0433\u043E\u0439, \u0441 \u0433\u043E\u043B\u043E\u0432\u043E\u0439 \u0443\u0432\u0435\u043D\u0447\u0430\u043D\u043D\u043E\u0439 \u0431\u0438\u043D\u0434\u0443 .</p></div><div class="stanza"><a href="#s8.40" id="s8.40" class="num">8.40</a><p>\u041E\u043D\u0430 \u0441\u0432\u044F\u0437\u0430\u043D\u0430 \u0441 \u043F\u0440\u0430\u0432\u044B\u043C \u043A\u043E\u043B\u0435\u043D\u043E\u043C, \u0432\u043C\u0435\u0449\u0430\u0435\u0442 \u0432\u0441\u0435 \u0441\u043E\u043D\u043C\u044B \u043C\u0430\u0442\u0435\u0440\u0435\u0439. \u0415\u044E (\u043E\u043D\u0438) \u0432\u0441\u0435 \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u044F\u044E\u0442\u0441\u044F, (\u043E\u043D\u0430) \u0434\u0430\u0435\u0442 \u0436\u0435\u043B\u0430\u043D\u043D\u044B\u0439 \u043F\u043B\u043E\u0434 .</p></div><div class="stanza"><a href="#s8.41" id="s8.41" class="num">8.41</a><p>\u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0432\u044B\u0441\u0448\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E \u041C\u0430\u0442\u0435\u0440\u0435\u0439, \u043F\u043E\u044D\u0442\u043E\u043C\u0443, \u0438\u0445 (\u043C\u0430\u043D\u0442\u0440\u044B) \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F\u0449\u0438\u0439 \u043C\u0430\u043D\u0442\u0440\u0443 \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u0439 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430 \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0438\u0442\u044C .</p></div><div class="stanza"><a href="#s8.42" id="s8.42" class="num">8.42</a><p>\u0412\u0435\u0447\u043D\u043E \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u043E \u0420\u0443\u0434\u0440\u044B \u0438 \u0428\u0430\u043A\u0442\u0438. \u0418\u0437 \u043D\u0435\u0433\u043E \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0412\u044B\u0441\u0448\u0430\u044F \u0428\u0430\u043A\u0442\u0438, \u0438\u043C\u0435\u043D\u0443\u0435\u043C\u0430\u044F (\u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0439) \u0432 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 .</p></div><div class="stanza"><a href="#s8.43" id="s8.43" class="num">8.43</a><p>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0432\u0441\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430 \u0432 \u043E\u0441\u043D\u043E\u0432\u0435 (\u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0442) \u0432 \u043D\u0435\u0439, \u0435\u044E \u043E\u043D\u0438 \u0442\u0432\u043E\u0440\u044F\u0442\u0441\u044F. \u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0435\u0435 \u0447\u0430\u0441\u0442\u0438 \u0442\u0435\u043B\u0430 \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0433\u043B\u0430\u0441\u043D\u044B\u043C\u0438, \u043A\u0430\u043A \u0440\u0430\u043D\u0435\u0435 (\u0432 \u0448\u0430\u0434\u0430\u043D\u0433\u0430 \u043D\u044C\u044F\u0441\u0435) .</p></div><div class="stanza"><a href="#s8.44-45" id="s8.44-45" class="num">8.44-45</a><p>\u041C\u0443\u0440\u0442\u0438 \u0441 \u0443\u0441\u0442\u0430\u043C\u0438, \u0428\u0430\u043A\u0442\u0438, \u0432\u0438\u0434\u044C\u044F- \u0442\u0440\u0435\u0442\u044C\u044F, \u0432\u043E\u0441\u044C\u043C\u0435\u0440\u043A\u0430, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0410\u0433\u0445\u043E\u0440\u0438, \u0438 \u0432\u0438\u0434\u044C\u044F\u043D\u0433\u0430 (\u043D\u044C\u044F\u0441\u0430)- \u043F\u044F\u0442\u0430\u044F. \u0412\u043C\u0435\u0441\u0442\u0435 \u0441 \u0447\u0430\u0441\u0442\u044F\u043C\u0438 \u0442\u0435\u043B\u0430 \u044D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u041D\u044C\u044F\u0441\u043E\u0439 \u0412\u044B\u0441\u0448\u0435\u0439 \u0428\u0430\u043A\u0442\u0438 \u0448\u0435\u0441\u0442\u0438 \u0432\u0438\u0434\u043E\u0432. \u0417\u0430 \u044D\u0442\u043E\u0439 \u043F\u0430\u0440\u043E\u0439 (\u043D\u044C\u044F\u0441) \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043D\u044C\u044F\u0441\u0430, \u0434\u0430\u044E\u0449\u0430\u044F \u0432\u0441\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430 .</p></div><div class="stanza"><a href="#s8.46" id="s8.46" class="num">8.46</a><p>\u041F\u0440\u0430\u0432\u0438\u043B\u043E \u043B\u0435\u0432\u043E\u0433\u043E \u0442\u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430 (<em>\u0442.\u0435. \u0442\u0430\u043D\u0442\u0440\u044B \u043B\u0435\u0432\u043E\u0439 \u0440\u0443\u043A\u0438</em>) \u0434\u043E\u043B\u0436\u043D\u043E \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u0441\u044F \u0447\u0435\u0440\u0435\u0437 \u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u0435 \u0432\u0430\u0440\u043D\u044B \u0438 \u043C\u0430\u043D\u0442\u0440\u044B \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u043C\u0438 \u043F\u043B\u043E\u0434\u0430 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u0438\u043B\u0438, \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E, \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u043C\u0438 (\u0434\u0440\u0443\u0433\u043E\u0433\u043E) \u043F\u043B\u043E\u0434\u0430 .</p></div><div class="stanza"><a href="#s8.47" id="s8.47" class="num">8.47</a><p>\u0414\u043B\u044F \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u0432\u0438\u0434\u0430 (\u043C\u0430\u043D\u0442\u0440), \u0440\u0430\u0437\u0434\u0435\u043B\u044F\u0435\u043C\u044B\u0445 \u043D\u0430 \u0428\u0430\u043C\u0431\u0445\u0443, \u0428\u0430\u043A\u0442\u0438 \u0438 \u0410\u043D\u0443 (\u043C\u0430\u043D\u0442\u0440\u044B), \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442\u0441\u044F \u0441\u0432\u043E\u044F \u043D\u044C\u044F\u0441\u0430 \u043F\u044F\u0442\u0438 \u0432\u0438\u0434\u043E\u0432 .</p></div><div class="stanza"><a href="#s8.48" id="s8.48" class="num">8.48</a><p>\u042D\u0442\u043E - \u0432\u043D\u0435\u0448\u043D\u044F\u044F (\u041D\u044C\u044F\u0441\u0430) \u0432\u043A\u043B\u044E\u0447\u0430\u0435\u0442 \u0442\u0430\u043A\u0436\u0435 \u0430\u043D\u0433\u0430 (\u043D\u044C\u044F\u0441\u0443). \u0428\u0435\u0441\u0442\u0430\u044F (<em>\u0432\u044C\u044F\u043F\u0430\u043A\u0430 \u043D\u044C\u044F\u0441\u0430</em>) (\u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442\u0441\u044F) \u043F\u043E\u0432\u0441\u044E\u0434\u0443 (<em>\u0442.\u0435. \u043F\u043E \u0432\u0441\u0435\u043C\u0443 \u0442\u0435\u043B\u0443</em>). \u0422\u0430\u043A \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043E\u0447\u0438\u0449\u0435\u043D\u0438\u0435 (\u0442\u0435\u043B\u0430) .</p></div><div class="stanza"><a href="#s8.49" id="s8.49" class="num">8.49</a><p>\u041D\u0435 \u043F\u0440\u0435\u0440\u044B\u0432\u0430\u044F \u0441\u0432\u043E\u0435\u0433\u043E \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u044F \u0432 \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0438 \u043E \u0441\u0443\u0449\u0435\u043C \u0438 \u043D\u0435- \u0441\u0443\u0449\u0435\u043C, \u043C\u0443\u0434\u0440\u044B\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0434\u0433\u043E\u0442\u043E\u0432\u0438\u0442\u044C \u043F\u043E\u0434\u043E\u0431\u0430\u044E\u0449\u0438\u0435 \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u044B \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u044F .</p></div><div class="stanza"><a href="#s8.50" id="s8.50" class="num">8.50</a><p>\u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u044C \u0441\u043E\u0441\u0443\u0434 \u0430\u0440\u0433\u0445\u044C\u0438, \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0449\u0438\u0439 \u0441\u0443\u0449\u0435\u0435 \u0438 \u043D\u0435-\u0441\u0443\u0449\u0435\u0435. \u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0437\u0430\u0436\u0438\u0433\u0430\u043D\u0438\u0435 \u043E\u0433\u043D\u044F \u0438 \u043E\u043C\u043E\u0432\u0435\u043D\u0438\u0435 \u0432\u043E\u0434\u043E\u0439 \u0428\u0430\u043A\u0442\u0438 \u0434\u043B\u044F \u043E\u0447\u0438\u0449\u0435\u043D\u0438\u044F .</p></div><div class="stanza"><a href="#s8.51" id="s8.51" class="num">8.51</a><p>\u041B\u0438\u0431\u043E \u043E\u0447\u0438\u0449\u0435\u043D\u0438\u0435 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442\u0441\u044F \u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u0430\u043C\u0438. \u0422\u0430\u043A\u0438\u043C \u043F\u0443\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0434\u0435\u0439\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C \u0437\u043D\u0430\u044E\u0449\u0435\u043C\u0443 .</p></div><div class="stanza"><a href="#s8.52" id="s8.52" class="num">8.52</a><p>\u041D\u0438 \u043A\u0430\u043A\u043E\u0439 \u043F\u0440\u0435\u0434\u043C\u0435\u0442 \u043D\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u0447\u0438\u0442\u0430\u0442\u044C \u043D\u0435\u0447\u0438\u0441\u0442\u044B\u043C. \u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u043C\u0443, \u0432\u0441\u0435 (\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F) \u0447\u0438\u0441\u0442\u044B\u043C, \u0434\u0430\u0436\u0435 \u043D\u0435\u0447\u0438\u0441\u0442\u043E\u0435 (\u0441\u0442\u0430\u043D\u0435\u0442) \u0447\u0438\u0441\u0442\u044B\u043C .</p></div><div class="stanza"><a href="#s8.53" id="s8.53" class="num">8.53</a><p>\u0412\u043E\u0434\u043E\u0439 \u043D\u0430\u043F\u043E\u043B\u043D\u0438\u0432 \u0441\u043E\u0441\u0443\u0434 \u0438 \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0432 \u0430\u043D\u0433\u0430 \u043D\u044C\u044F\u0441\u0443 \u0438 \u0430\u043C\u0440\u0438\u0442\u0430\u043A\u0430\u0440\u043D\u0443, \u044D\u0442\u043E\u0439 \u0432\u043E\u0434\u043E\u0439 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0447\u0438\u0441\u0442\u0438\u0442\u044C \u0432\u0441\u0435 \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u044B .</p></div><div class="stanza"><a href="#s8.54" id="s8.54" class="num">8.54</a><p>\u041F\u043E\u0447\u0442\u0438\u0432 \u0410\u0442\u043C\u0430\u043D, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435 (\u043F\u043E\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u0435). \u041F\u043E\u0432\u0435\u0434\u0430\u044E \u0442\u0435\u043F\u0435\u0440\u044C \u0422\u0435\u0431\u0435 (\u0434\u0430\u043B\u044C\u043D\u0435\u0439\u0448\u0435\u0435), \u043E \u041F\u043E\u0447\u0438\u0442\u0430\u0435\u043C\u0430\u044F \u0432\u0441\u0435\u043C\u0438 \u0441\u043E\u043D\u043C\u0430\u043C\u0438 \u0439\u043E\u0433\u043E\u0432!</p></div><div class="stanza"><a href="#s8.55" id="s8.55" class="num">8.55</a><p>\u0412\u043D\u0430\u0447\u0430\u043B\u0435 (\u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C) \u043D\u0430 \u0447\u0435\u0442\u044B\u0440\u0435 \u0430\u043D\u0433\u0443\u043B\u044B \u043D\u0438\u0436\u0435 \u043F\u0443\u043F\u043A\u0430 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u044E\u0449\u0438\u0435 (\u0430\u0434\u0445\u0430\u0440\u0430) \u0448\u0430\u043A\u0442\u0438: \u0414\u0445\u0430\u0440\u0443, \u0421\u0443\u0440\u043E\u0434\u0443, \u041F\u043E\u0442\u0443 \u0438 \u041A\u0430\u043D\u0434\u0443, \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0443\u044E .</p></div><div class="stanza"><a href="#s8.56" id="s8.56" class="num">8.56</a><p>(\u0422\u043E\u0447\u043A\u0430 \u043D\u0430) \u0447\u0435\u0442\u044B\u0440\u0435 \u0430\u043D\u0433\u0443\u043B\u044B (\u043D\u0438\u0436\u0435 \u043F\u0443\u043F\u043A\u0430) \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0438\u0441\u0442\u043E\u043A\u043E\u043C \u0442\u0440\u0435\u0437\u0443\u0431\u0446\u0430. \u0412 \u0435\u0433\u043E \u0440\u0443\u043A\u043E\u044F\u0442\u0438 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u041D\u0430\u043B\u0443 \u0438 \u0410\u043D\u0430\u043D\u0442\u0443 .</p></div><div class="stanza"><a href="#s8.57" id="s8.57" class="num">8.57</a><p>\u0412\u044B\u0448\u0435 \u041B\u0430\u043C\u0431\u0438\u043A\u0438 (<em>\u0438\u043D\u0434\u0440\u0430-\u0439\u043E\u043D\u0438 \u0447\u0430\u043A\u0440\u0430, \u043C\u0435\u0436\u0434\u0443 \u043D\u043E\u0441\u043E\u043C \u0438 \u0433\u043E\u0440\u043B\u043E\u043C</em>), \u0432\u0432\u0435\u0440\u0445\u0443 \u0442\u0440\u0435\u0437\u0443\u0431\u0446\u0430 - \xAB\u044F\u0431\u043B\u043E\u043A\u043E\xBB. \u0418\u043C \u043F\u0440\u043E\u0431\u0438\u0432\u0430\u0435\u0442\u0441\u044F, \u043E \u041C\u0430\u0445\u0430\u0434\u0435\u0432\u0430, \u0432\u0435\u043B\u0438\u043A\u0438\u0439 \u043E\u043A\u0435\u0430\u043D \u0441\u0435\u0442\u0438 \u043E\u043A\u043E\u0432 .</p></div><div class="stanza"><a href="#s8.58-59" id="s8.58-59" class="num">8.58-59</a><p>\u0411\u0435\u0437 \u043D\u0435\u0433\u043E \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u043D\u0435 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 \u0441 \u0428\u0438\u0432\u043E\u0439 (\u0428\u0438\u0432\u0430 \u0439\u043E\u0433\u0438). (\u0412\u043E\u043A\u0440\u0443\u0433 \u043D\u0435\u0433\u043E), \u043F\u043E \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u0447\u043D\u044B\u043C \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F\u043C, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u044E\u0433\u043E-\u0432\u043E\u0441\u0442\u043E\u0447\u043D\u043E\u0433\u043E, \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F\u0449\u0438\u0439 \u043C\u0430\u043D\u0442\u0440\u0443 \u0434\u043E\u043B\u0436\u0435\u043D \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0414\u0445\u0430\u0440\u043C\u0443, \u0414\u0436\u043D\u0430\u043D\u0443, \u0412\u0430\u0439\u0440\u0430\u0433\u044C\u044E \u0438 \u0410\u0439\u0448\u0432\u0430\u0440\u044C\u044E - \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0443\u044E. \u041F\u043E \u0447\u0435\u0442\u044B\u0440\u0435\u043C (\u043E\u0441\u043D\u043E\u0432\u043D\u044B\u043C) \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F\u043C, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0432\u043E\u0441\u0442\u043E\u043A\u0430, \u043E\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u0430\u043C\u044F\u0442\u043E\u0432\u0430\u0442\u044C \u0447\u0435\u0442\u044B\u0440\u0451\u0445 \u0441\u043B\u043E\u043D\u043E\u0432- \u0437\u0435\u043C\u043B\u0435\u0434\u0435\u0440\u0436\u0446\u0435\u0432 .</p></div><div class="stanza"><a href="#s8.60" id="s8.60" class="num">8.60</a><p>\u0412\u044B\u0448\u0435 \xAB\u044F\u0431\u043B\u043E\u043A\u0430\xBB, \u043D\u0438\u0436\u0435 \u0442\u0440\u0435\u0437\u0443\u0431\u0446\u0430 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442\u0441\u044F \u0447\u0435\u0442\u0432\u0435\u0440\u043A\u0430. \u0415\u0435 \u0438\u043C\u0435\u043D\u0443\u044E\u0442 \u0432\u0438\u0434\u044C\u044F \u0442\u0430\u0442\u0442\u0432\u043E\u0439, \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0442\u0440\u0435\u043C\u044F \u0435\u0435 \u043F\u043E\u043A\u0440\u043E\u0432\u0430\u043C\u0438 .</p></div><div class="stanza"><a href="#s8.61" id="s8.61" class="num">8.61</a><p>\u042D\u0442\u0443 \u0442\u0430\u0442\u0442\u0432\u0443 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u043C\u0435\u0436\u0434\u0443 \u041A\u0410- \u041A\u0425\u0410 (<em>\u0442.\u0435. \u0442\u0440\u0435\u0443\u0433\u043E\u043B\u044C\u043D\u0438\u043A\u043E\u043C \u0410-\u041A\u0410-\u041A\u0425\u0410</em>) \u0438 \u041B\u0430\u043C\u0431\u0438\u043A\u043E\u0439. \u041F\u0443\u0441\u0442\u044C \u043C\u0443\u0434\u0440\u044B\u0439 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442 \u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u041A\u0410 \u0438 \u041A\u0425\u0410 \u0442\u0430\u0442\u0442\u0432\u0443 \u0432 \u0444\u043E\u0440\u043C\u0435 \u043B\u043E\u0442\u043E\u0441\u0430;</p></div><div class="stanza"><a href="#s8.62" id="s8.62" class="num">8.62</a><p>\u041D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0433\u043E \u0432\u0435\u043D\u0447\u0438\u043A\u043E\u043C \u0438 \u0442\u044B\u0447\u0438\u043D\u043A\u0430\u043C\u0438, \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0440\u0430\u0441\u043A\u0440\u044B\u0432\u0430\u044E\u0449\u0438\u043C\u0441\u044F \u0431\u0435\u043B\u044B\u043C \u0441\u0435\u043C\u0435\u043D\u0435\u043C. \u041D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0432\u043E\u0441\u0442\u043E\u0447\u043D\u043E\u0433\u043E \u043B\u0435\u043F\u0435\u0441\u0442\u043A\u0430 (\u0432 \u043D\u0435\u043C) \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0434\u0435\u0432\u044F\u0442\u043A\u0443, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0412\u0430\u043C\u044B .</p></div><div class="stanza"><a href="#s8.63-64" id="s8.63-64" class="num">8.63-64</a><p>\u0412\u0430\u043C\u0430, \u0414\u0436\u044C\u0435\u0448\u0442\u0445\u0430, \u0420\u0430\u0443\u0434\u0440\u0438, \u041A\u0430\u043B\u0438, \u041A\u0430\u043B\u0430\u0432\u0438\u043A\u0430\u0440\u0430\u043D\u0438, \u0421\u0430\u0440\u0432\u0430\u0431\u0445\u0443\u0442\u0430\u0434\u0430\u043C\u0430\u043D\u0438 \u0438 \u041C\u0430\u043D\u043E\u043D\u043C\u0430\u043D\u0438 \u0432 \u0446\u0435\u043D\u0442\u0440\u0435- \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u043F\u043E \u0445\u043E\u0434\u0443 \u0441\u043E\u043B\u043D\u0446\u0430 .</p></div><div class="stanza"><a href="#s8.65-66" id="s8.65-66" class="num">8.65-66</a><p>\u0412 \u043E\u0431\u0440\u0430\u0442\u043D\u043E\u043C \u043F\u043E\u0440\u044F\u0434\u043A\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0434\u0440\u0443\u0433\u0443\u044E \u0434\u0435\u0432\u044F\u0442\u043A\u0443, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0412\u0438\u0431\u0445\u0443: \u0412\u0438\u0431\u0445\u0443, \u0414\u0436\u043D\u0430\u043D\u0438, \u041A\u0440\u0438\u044F, \u0427\u0435\u0448\u0442\u0432\u0430, \u0412\u0430\u0433\u0438\u0448\u0438, \u0414\u0436\u0432\u0430\u043B\u0438\u043D\u0438, \u0412\u0430\u043C\u0430, \u0414\u0436\u044C\u0435\u0448\u0442\u0445\u0430, \u0420\u0430\u0443\u0434\u0440\u0438, \u0432\u0441\u0435 \u0441\u0438\u044F\u044E\u0449\u0438\u0435 \u043A\u0430\u043A \u043E\u0433\u043E\u043D\u044C \u043A\u043E\u043D\u0446\u0430 \u0432\u0440\u0435\u043C\u0435\u043D. \u0421\u043D\u0430\u0447\u0430\u043B\u0430 \u0440\u0430\u0437\u043C\u0435\u0449\u0430\u044E\u0442\u0441\u044F \u0448\u0430\u043A\u0442\u044B: \u0411\u0440\u0430\u0445\u043C\u0430, \u0412\u0438\u0448\u043D\u0443 \u0438 \u0425\u0430\u0440\u0430 .</p></div><div class="stanza"><a href="#s8.67" id="s8.67" class="num">8.67</a><p>\u0412 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435, \u0432\u0435\u043D\u0447\u0438\u043A\u0435 \u0432 \u043B\u0435\u043F\u0435\u0441\u0442\u043A\u0430\u0445 \u043C\u0430\u043D\u0434\u0430\u043B \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0442 \u044D\u0442\u0438 \u0432\u043B\u0430\u0434\u044B\u043A\u0438. \u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0438\u0445, \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u043C\u044B\u0445 \u0420\u0435\u0447\u044C\u044E, \u0421\u043E\u043B\u043D\u0446\u0435\u043C, \u041B\u0443\u043D\u043E\u0439 \u0438 \u043E\u0433\u043D\u0435\u043C .</p></div><div class="stanza"><a href="#s8.68" id="s8.68" class="num">8.68</a><p>\u0418\u0448\u0432\u0430\u0440\u0430, \u041C\u0430\u0445\u0430\u043F\u0440\u0435\u0442\u0430, \u0421\u0438\u044F\u044E\u0449\u0438\u0439, \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0443\u043C\u043E\u043C, \u043E\u0431\u043B\u0430\u0434\u0430\u044E\u0449\u0438\u0439 \u0442\u0435\u043B\u043E\u043C (\u0441\u0438\u044F\u044E\u0449\u0438\u043C) \u043A\u0430\u043A \u0434\u0435\u0441\u044F\u0442\u044C \u043C\u0438\u043B\u043B\u0438\u043E\u043D\u043E\u0432 \u043E\u0433\u043D\u0435\u0439 \u0432\u0435\u0447\u043D\u043E\u0441\u0442\u0438 - \u043C\u0435\u0441\u0442\u043E \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u044F \u0438\u0445 \u0432\u0441\u0435\u0445 .</p></div><div class="stanza"><a href="#s8.69" id="s8.69" class="num">8.69</a><p>\u0418\u0437 \u0435\u0433\u043E \u043F\u0443\u043F\u043A\u0430 \u0432\u044B\u0440\u0430\u0441\u0442\u0430\u0435\u0442 \u0428\u0430\u043A\u0442\u0438. \u0415\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u043A\u0430\u043A \u0442\u0440\u0438 \u0437\u0443\u0431\u0446\u0430 \u0442\u0440\u0435\u0437\u0443\u0431\u0446\u0430. \u0422\u0440\u0435\u0445\u043A\u043E\u043D\u0435\u0447\u043D\u044B\u0439 \u041A\u0410-\u041A\u0425\u0410 \u0443\u043F\u0438\u0440\u0430\u0435\u0442\u0441\u044F \u0432 \u0434\u0432\u0430\u0434\u0430\u0448\u0430\u043D\u0442\u0443 .</p></div><div class="stanza"><a href="#s8.70" id="s8.70" class="num">8.70</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0432 \u0435\u0433\u043E \u0437\u0443\u0431\u0446\u0430\u0445 \u0442\u0440\u0438 \u043B\u043E\u0442\u043E\u0441\u0430 \u0428\u0430\u043A\u0442\u0438. \u0411\u0435\u043B\u044B\u0439, \u0432\u0441\u0435\u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u044E\u0449\u0438\u0439- \u0442\u0430\u043A\u043E\u0432\u0430 \u0430\u0441\u0430\u043D\u0430 \u041F\u0430\u0440\u0430 (\u0448\u0430\u043A\u0442\u0438) .</p></div><div class="stanza"><a href="#s8.71" id="s8.71" class="num">8.71</a><p>\u041D\u0430 \u043D\u0435\u0439 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u043E\u0431\u0440\u0430\u0437, \u0438\u043C\u0435\u043D\u0443\u0435\u043C\u044B\u0439 \u0412\u0438\u0434\u044C\u0435\u0439, \u0432 \u043D\u0435\u0439 -\u0410\u0442\u043C\u0430\u043D, \u0432 \u043D\u0435\u0433\u043E (\u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442\u0441\u044F) \u043F\u0443\u0440\u0432\u0430 \u043D\u044C\u044F\u0441\u0430, \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u0430\u044F \u0428\u0438\u0432\u043E\u0439 .</p></div><div class="stanza"><a href="#s8.72" id="s8.72" class="num">8.72</a><p>\u0417\u0430\u0442\u0435\u043C \u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0443 \u043C\u0435\u0436\u0434\u0443 \u0434\u0432\u0443\u043C\u044F (\u0437\u0443\u0431\u0446\u0430\u043C\u0438), \u0441\u0435\u0432\u0435\u0440\u043D\u044B\u043C \u0438 \u044E\u0436\u043D\u044B\u043C (\u043F\u043E\u043C\u0435\u0449\u0430\u0435\u0442\u0441\u044F) \u0432\u044B\u0441\u0448\u0430\u044F \u0428\u0430\u043A\u0442\u0438, \u0432 \u0444\u043E\u0440\u043C\u0435 \u041F\u0430\u0440\u0430\u043F\u0430\u0440\u0430, \u0432\u0435\u043B\u0438\u043A\u043E\u0441\u0438\u043B\u044C\u043D\u0430\u044F, \u043A\u0440\u0430\u0441\u043D\u043E\u0433\u043E \u0446\u0432\u0435\u0442\u0430 .</p></div><div class="stanza"><a href="#s8.73" id="s8.73" class="num">8.73</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0435\u0435 \u043A\u0430\u043A \u0413\u0440\u043E\u0437\u043D\u0443\u044E, \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0443\u044E \u0444\u043E\u0440\u043C\u0443 \u0412\u043E\u043B\u0438, \u043D\u0435\u0443\u0441\u0442\u0440\u0430\u0448\u0438\u043C\u0443\u044E. \u0412 \u043B\u0435\u0432\u043E\u043C \u0437\u0443\u0431\u0446\u0435- \u0410\u043F\u0430\u0440\u0430, \u041A\u0440\u0430\u0441\u043D\u043E- \u0447\u0435\u0440\u043D\u0430\u044F, \u0443\u0441\u0442\u0440\u0430\u0448\u0430\u044E\u0449\u0430\u044F .</p></div><div class="stanza"><a href="#s8.74" id="s8.74" class="num">8.74</a><p>\u0414\u0435\u0432\u0438, \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0430\u044F \u0444\u043E\u0440\u043C\u0443 \u0412\u043E\u043B\u0438, \u041F\u043E\u0447\u0438\u0442\u0430\u0435\u043C\u0430\u044F, \u0423\u043D\u0438\u0447\u0442\u043E\u0436\u0438\u0442\u0435\u043B\u044C\u043D\u0438\u0446\u0430 \u0431\u0435\u0434, \u0412\u044B\u0441\u0448\u0430\u044F (\u041F\u0430\u0440\u0430) \u041F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0430\u044F \u0414\u0435\u0432\u0438, \u0421\u0438\u044F\u044E\u0449\u0430\u044F \u043A\u0430\u043A \u043C\u0438\u043B\u043B\u0438\u0430\u0440\u0434 \u0441\u043E\u043B\u043D\u0446 .</p></div><div class="stanza"><a href="#s8.75" id="s8.75" class="num">8.75</a><p>\u0412 \u0448\u0430\u043A\u0442\u0438 \u0448\u0435\u0441\u0442\u0438 \u0432\u0438\u0434\u043E\u0432 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u044D\u0442\u0438 \u043E\u0431\u0440\u0430\u0437\u044B. \u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0447\u0430\u0441\u0442\u0438 \u0442\u0435\u043B\u0430 \u043F\u044F\u0442\u0435\u0440\u043A\u0438 \u0432\u0438\u0434\u0438\u0439, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u044E\u0433\u043E-\u0432\u043E\u0441\u0442\u043E\u043A\u0430 .</p></div><div class="stanza"><a href="#s8.76" id="s8.76" class="num">8.76</a><p>\u0412 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F\u0445 \u0410\u0433\u043D\u0438, \u0418\u0448\u044B, \u0420\u0430\u043A\u0448\u0438, \u0412\u0430\u044E, \u0438 \u042E\u0433\u0430, \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u043A\u0430\u043A \u043F\u043E\u0434\u043E\u0431\u0430\u0435\u0442, \u0447\u0430\u0441\u0442\u0438 \u0442\u0435\u043B\u0430 \u0428\u0430\u043A\u0442\u0438, \u0438 \u0447\u0430\u0441\u0442\u0438 \u0442\u0435\u043B\u0430 \u0428\u0438\u0432\u044B .</p></div><div class="stanza"><a href="#s8.77" id="s8.77" class="num">8.77</a><p>(\u0422\u0430\u043A \u0436\u0435 \u0438) \u041F\u043E \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u043D\u0438\u044F\u043C, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0428\u0430\u043A\u0440\u044B \u0441 \u0430\u0441\u0442\u0440\u0430 \u043C\u0430\u043D\u0442\u0440\u043E\u0439. \u0412 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0443 (\u0440\u0430\u0437\u043C\u0435\u0449\u0430\u0435\u0442\u0441\u044F) \xAB\u0433\u043B\u0430\u0437\xBB. \u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C (\u043F\u043E \u044D\u0442\u0438\u043C \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F\u043C)\u0432\u043E\u0441\u044C\u043C\u0435\u0440\u043A\u0443, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0410\u0433\u0445\u043E\u0440\u044B, \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0432\u043E\u0441\u044C\u043C\u0435\u0440\u043A\u043E\u0439, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0410\u0433\u0445\u043E\u0440\u0438 .</p></div><div class="stanza"><a href="#s8.78" id="s8.78" class="num">8.78</a><p>\u0421\u043D\u0430\u0440\u0443\u0436\u0438 \u0440\u0430\u0432\u043D\u043E\u043C\u0435\u0440\u043D\u043E, \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443 (\u0440\u0430\u0437\u043C\u0435\u0449\u0430\u044E\u0442\u0441\u044F) \u043B\u043E\u043A\u0430\u043F\u0430\u043B\u044B. \u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0438\u0445 \u0432\u0441\u0435\u0445 \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0438\u0445 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u043C\u0430\u043D\u0442\u0440\u0430\u043C\u0438, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0437\u0430\u0442\u0435\u043C \u043F\u0440\u0438\u0441\u0442\u0443\u043F\u0438\u0442\u044C \u043A \u0434\u0436\u0430\u043F\u0435 .</p></div><div class="stanza"><a href="#s8.79" id="s8.79" class="num">8.79</a><p>(\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F, \u043A\u0430\u043A \u043E\u043D\u0438) \u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u044B\u043C\u0438 \u0432 \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u0435, \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0434\u0435\u0441\u044F\u0442\u0438\u043A\u0440\u0430\u0442\u043D\u043E. \u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0441\u0438\u044F\u044E\u0449\u0435\u0435 \u043F\u043B\u0430\u043C\u044F \u043E\u0433\u043D\u044F, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432 \u043A\u043E\u043D\u0446\u0435 \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0442\u0438 \u0421\u0412\u0410\u0425\u0410 .</p></div><div class="stanza"><a href="#s8.80" id="s8.80" class="num">8.80</a><p>\u041F\u0443\u0441\u0442\u044C \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F\u0449\u0438\u0439 \u043C\u0430\u043D\u0442\u0440\u0443 \u0441\u0434\u0435\u043B\u0430\u0435\u0442 \u0442\u0430\u043A \u043E\u0434\u0438\u043D \u0440\u0430\u0437, (\u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F) \u043E\u0434\u043D\u043E\u0433\u043E \u0437\u0430 \u0434\u0440\u0443\u0433\u0438\u043C, \u0440\u0430\u0434\u0438 \u0443\u0441\u043F\u0435\u0445\u0430 \u0432 \u043E\u0431\u0440\u044F\u0434\u0435 \u0445\u043E\u043C\u044B. \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u043C \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u0435\u043C \u0441\u0430\u043C\u0443\u0434\u0430\u044F\u043A\u0430 .</p></div><div class="stanza"><a href="#s8.81" id="s8.81" class="num">8.81</a><p>\u0422\u0430\u043A (\u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442\u0441\u044F) \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0430 \u0442\u0440\u0438\u0448\u0443\u043B\u044B \u0441 \u043E\u0434\u043D\u043E\u0439 \u0440\u0443\u043A\u043E\u044F\u0442\u044C\u044E, \u0438 \u0442\u0440\u0435\u043C\u044F \u0428\u0430\u043A\u0442\u0438. \u0422\u0430\u043A (\u0438\u0441\u043F\u0440\u0430\u0448\u0438\u0432\u0430\u0435\u0442\u0441\u044F) \u043F\u043E\u0432\u0435\u043B\u0435\u043D\u0438\u0435 \u0443 \u0442\u0440\u0435\u0437\u0443\u0431\u0446\u0430, \u043E \u041F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u043E\u043B\u0438\u043A\u0430\u044F!</p></div><div class="stanza"><a href="#s8.82" id="s8.82" class="num">8.82</a><p>\u041F\u0440\u0438\u043D\u044F\u0432 \u043A\u0445\u0435\u0447\u0430\u0440\u0438 \u043C\u0443\u0434\u0440\u0443, \u043D\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0442\u0440\u044B\u0432\u0430\u0442\u044C\u0441\u044F \u043E\u0442 \u043F\u043E\u0432\u0435\u0440\u0445\u043D\u043E\u0441\u0442\u0438 \u0437\u0435\u043C\u043B\u0438. \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0448\u0430\u043C\u0431\u0445\u0430\u0432\u0430 (\u0434\u0445\u044C\u044F\u043D\u0430), \u043F\u043E\u0441\u043B\u0435 \u0432\u043E\u0441\u044C\u043C\u043E\u0439 (\u0447\u0430\u043A\u0440\u044B) \u043E\u043D\u0430 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0448\u0430\u043A\u0442\u0430 .</p></div><div class="stanza"><a href="#s8.83" id="s8.83" class="num">8.83</a><p>\u041F\u043E\u0441\u043B\u0435 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0439 \u043E\u043D\u0430 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 \u043A\u0430\u043A \u0430\u043D\u0430\u0432\u0430. \u0422\u0430\u043A\u043E\u0432\u0430 \u0442\u0440\u0438\u0448\u0443\u043B\u0430. \u041E\u0442\u0434\u0435\u043B\u044C\u043D\u043E \u043E\u0442 \u043E\u0431\u0440\u044F\u0434\u0430 \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u044F \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0448\u0430\u043A\u0442\u0438 \u0447\u0430\u043A\u0440\u0443 .</p></div><div class="stanza"><a href="#s8.84-85" id="s8.84-85" class="num">8.84-85</a><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u043C\u0443, \u043F\u0440\u0438\u043D\u044F\u0432 \u043A\u0445\u0435\u0447\u0430\u0440\u0438 (\u043C\u0443\u0434\u0440\u0443) \u0439\u043E\u0433\u0438\u043D \u0441\u043C\u043E\u0436\u0435\u0442 \u043E\u0442\u043E\u0440\u0432\u0430\u0442\u044C\u0441\u044F \u043E\u0442 \u043F\u043E\u0432\u0435\u0440\u0445\u043D\u043E\u0441\u0442\u0438 \u0437\u0435\u043C\u043B\u0438. \u0417\u0430\u0442\u0435\u043C, \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F \u043C\u0430\u043D\u0442\u0440\u0443 \u0441 \u043C\u0430\u0445\u0430\u0441\u0442\u0440\u043E\u0439 10 \u0440\u0430\u0437, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u0431\u0440\u043E\u0441\u0430\u0442\u044C \u043F\u043E \u0432\u0441\u0435\u043C \u0441\u0442\u043E\u0440\u043E\u043D\u0430\u043C \u0441\u0432\u0435\u0442\u0430 \u0434\u0435\u043D\u044C\u0433\u0438, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F (\u043A\u0430\u043A \u043E\u043D\u0438 \u0441\u0433\u043E\u0440\u0430\u044E\u0442) \u0441\u043B\u043E\u0432\u043D\u043E \u043E\u0442 \u043F\u043B\u0430\u043C\u0435\u043D\u0438 \u043E\u0433\u043D\u044F. \u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0434\u043E\u043C (\u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u044F) \u043B\u0438\u0448\u0435\u043D\u043D\u044B\u043C \u043F\u0440\u0435\u043F\u044F\u0442\u0441\u0442\u0432\u0438\u0439, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0432\u0435\u0440\u043D\u0443\u0442\u044C\u0441\u044F \u043D\u0430 \u0441\u0435\u0432\u0435\u0440\u043E-\u0432\u043E\u0441\u0442\u043E\u043A (\u0443\u0434\u0430\u043B\u0438\u0432 \u0438\u0445) .</p></div><div class="stanza"><a href="#s8.86" id="s8.86" class="num">8.86</a><p>\u0417\u0430\u0442\u0435\u043C \u043F\u0443\u0441\u0442\u044C \u043C\u0443\u0434\u0440\u044B\u0439 \u0441\u0434\u0435\u043B\u0430\u0435\u0442 \u043F\u0430\u043D\u044C\u0447\u0430 \u0433\u0430\u0432\u044C\u044E \u0438\u0437 \u043F\u044F\u0442\u0438 \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u043E\u0432. (\u042D\u0442\u043E): \u043A\u043E\u0440\u043E\u0432\u044C\u044F \u043C\u043E\u0447\u0430, \u043D\u0430\u0432\u043E\u0437, \u043C\u043E\u043B\u043E\u043A\u043E, \u043F\u0440\u043E\u0441\u0442\u043E\u043A\u0432\u0430\u0448\u0430 \u0438 \u043C\u0430\u0441\u043B\u043E .</p></div><div class="stanza"><a href="#s8.87" id="s8.87" class="num">8.87</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0442\u0438 \u043C\u0430\u043D\u0442\u0440\u0443 \u0448\u0430\u0434\u0430\u043D\u0433\u0430 (\u043D\u044C\u044F\u0441\u044B) \u0441\u0432\u0435\u0440\u0445\u0443 \u0438 \u0432\u043E\u043A\u0440\u0443\u0433, (\u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044F) \u0432\u043E\u0434\u0443 \u0438 \u0442\u0440\u0430\u0432\u0443 \u043A\u0443\u0448\u0430. \u0412\u044B\u043F\u043E\u043B\u043D\u0438\u0432 \u0430\u043C\u0440\u0438\u0442\u0430 (\u043A\u0430\u0440\u0430\u043D\u0430) \u043C\u0443\u0434\u0440\u0443 \u043D\u0430\u0434 \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u0430\u043C\u0438 (\u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u044F), \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0446\u0430\u0442\u044C \u0435\u0433\u043E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C .</p></div><div class="stanza"><a href="#s8.88" id="s8.88" class="num">8.88</a><p>\u041F\u0443\u0441\u0442\u044C \u0437\u0430\u0442\u0435\u043C \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442 \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u0435 \u0432\u0430\u0441\u0442\u0443 (\u043F\u0443\u0440\u0443\u0448\u0435), \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F \u043C\u0430\u043B\u0438\u043D\u0438 .</p></div><div class="stanza"><a href="#s8.89" id="s8.89" class="num">8.89</a><p>\u0421\u043B\u043E\u0436\u0438\u0432 \u0440\u0443\u043A\u0438 \u0432 \u0430\u043D\u0434\u0436\u0430\u043B\u0438 (\u043C\u0443\u0434\u0440\u0443) \u0438 \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F (\u0441\u043B\u043E\u0433\u0438), \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u041F\u0425\u0410 (\u0425\u0410), \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0430\u0434\u0445\u0432\u0443 \u0437\u0430\u043A\u043D\u0447\u0438\u0432\u0430\u044E\u0449\u0443\u044E\u0449\u0443\u0441\u044F \u043D\u0430 \u0428\u0430\u043A\u0442\u0438 \u0438 \u043F\u043E\u0441\u043B\u0435 \u0441\u043B\u043E\u0433\u0430 \u041D\u0410 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0431\u0440\u043E\u0441\u0438\u0442\u044C (\u043F\u043E\u0434\u043D\u043E\u0448\u0435\u043D\u0438\u0435) .</p></div><div class="stanza"><a href="#s8.90" id="s8.90" class="num">8.90</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0447\u0438\u0442\u0430\u0442\u044C \u0413\u0430\u043D\u0435\u0448\u0443, \u043F\u043E\u0434\u043D\u043E\u0441\u044F \u0431\u043B\u0430\u0433\u043E\u0432\u043E\u043D\u0438\u044F, \u043A\u0443\u0440\u0435\u043D\u0438\u044F \u0438 \u043F\u0440\u043E\u0447\u0435\u0435. \u041D\u0430 \u0430\u0441\u0430\u043D\u0443 \u043F\u043E\u043C\u0435\u0449\u0430\u044E\u0442\u0441\u044F \u0441\u0432\u0435\u0440\u0445\u0443 (\u043F\u043E\u0434\u043D\u043E\u0448\u0435\u043D\u0438\u044F) \u0441 \u0448\u0435\u0441\u0442\u044C\u044E \u043F\u0440\u043E\u0437\u043D\u043E\u0448\u0435\u043D\u0438\u044F\u043C\u0438 \u043F\u0440\u0430\u043D\u0430\u0432\u044B .</p></div><div class="stanza"><a href="#s8.91" id="s8.91" class="num">8.91</a><p>(\u041F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F \u0441\u043B\u043E\u0433) \u0413\u0410\u041C, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0436\u0435\u0440\u0442\u0432\u043E\u0432\u0430\u0442\u044C \u0412\u0438\u0433\u043D\u0435\u0448\u0435 \u0431\u043B\u0430\u0433\u043E\u0432\u043E\u043D\u0438\u044F, \u043A\u0443\u0440\u0435\u043D\u0438\u044F \u0438 \u043F\u0440\u043E\u0447\u0435\u0435. \u0415\u0433\u043E \u0410\u043D\u0433\u0430 (\u041D\u044C\u044F\u0441\u0430) \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442\u0441\u044F \u0441 \u0448\u0435\u0441\u0442\u044C\u044E \u0434\u043E\u043B\u0433\u0438\u043C\u0438 \u0433\u043B\u0430\u0441\u043D\u044B\u043C\u0438 .</p></div><div class="stanza"><a href="#s8.92" id="s8.92" class="num">8.92</a><p>\u041F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F \u0442\u0440\u0438\u043D\u0435\u0442\u0440\u0443, \u0438 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0413\u0430\u0434\u0436\u0443, \u0432 \u043E\u0431\u0440\u0430\u0437\u0435 \u0412\u0430\u043C\u044B. \u041E\u0442\u043F\u0443\u0441\u043A\u0430\u044F (\u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0442\u0438): \u0414\u0430 \u0431\u0443\u0434\u0435\u0442 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E. \u0422\u0430\u043A \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0447\u0438\u0442\u0430\u0442\u044C \u0432\u0435\u043B\u0438\u043A\u043E\u0435 \u043E\u0440\u0443\u0436\u0438\u0435 .</p></div><div class="stanza"><a href="#s8.93" id="s8.93" class="num">8.93</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0410\u043D\u0430\u043D\u0442\u0443, \u0414\u0445\u0430\u0440\u043C\u0443, \u0414\u0436\u043D\u0430\u043D\u0443 \u0438 \u0412\u0430\u0439\u0440\u0430\u0433\u044C\u044E \u0438 \u0410\u0439\u0448\u0432\u0430\u0440\u044C\u044E \u0432 \u0432\u0435\u043D\u0447\u0438\u043A\u0435. \u0422\u0430\u043A\u043E\u0432\u0430 \u0430\u0441\u0430\u043D\u0430, (\u0438\u043C\u0435\u044E\u0449\u0430\u044F) \u0448\u0435\u0441\u0442\u044C \u043E\u043F\u043E\u0440 .</p></div><div class="stanza"><a href="#s8.95" id="s8.95" class="num">8.95</a><p>\u0412\u044B\u0448\u0435 \u043D\u0435\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0442\u044C, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F, (\u0428\u0438\u0432\u0443), \u0434\u0435\u0440\u0436\u0430\u0449\u0435\u0433\u043E \u043C\u0435\u0447 \u0438 \u0446\u0432\u0435\u0442\u043E\u043A \u043A\u0435\u0442\u0430\u043A\u0438, \u0443\u0441\u0442\u0440\u0430\u0448\u0430\u044E\u0449\u0435\u0433\u043E, \u0441 \u043E\u0433\u0440\u043E\u043C\u043D\u044B\u043C\u0438 \u043A\u043B\u044B\u043A\u0430\u043C\u0438, \u0441 \u043B\u0438\u0446\u043E\u043C \u0443\u043A\u0440\u0430\u0448\u0435\u043D\u043D\u044B\u043C \u0441\u0440\u043E\u0441\u0448\u0438\u043C\u0438\u0441\u044F \u0431\u0440\u043E\u0432\u044F\u043C\u0438, \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0433\u043E \u0448\u0435\u0441\u0442\u044C\u044E \u0435\u0433\u043E \u0447\u0430\u0441\u0442\u044F\u043C\u0438, \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u043D\u043E\u0433\u043E \u043F\u043E \u0441\u0442\u043E\u0440\u043E\u043D\u0430\u043C \u0441\u0432\u0435\u0442\u0430 \u041C\u0430\u0442\u0435\u0440\u044F\u043C\u0438, \u043E\u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u0448\u0435\u0441\u0442\u044C\u044E \u0447\u0430\u0441\u0442\u044F\u043C\u0438 \u0420\u0435\u0432\u044B, \u0438 \u0441\u043B\u043E\u0433\u043E\u043C \u041F\u0425\u0410\u0422 .</p></div><div class="stanza"><a href="#s8.96" id="s8.96" class="num">8.96</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0442\u0430\u043A\u0443\u044E \u0444\u043E\u0440\u043C\u0443, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0437\u0430\u0442\u0435\u043C \u043F\u043E\u0447\u0438\u0442\u0430\u0442\u044C \u0432\u043E\u0441\u044C\u043C\u0435\u0440\u043A\u0443 \u041C\u0430\u0442\u0435\u0440\u0435\u0439. \u0412 \u0432\u043E\u0441\u0442\u043E\u0447\u043D\u043E\u043C \u043B\u0435\u043F\u0435\u0441\u0442\u043A\u0435, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0418\u043D\u0434\u0440\u0430\u043D\u0438 \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0432\u0430\u0434\u0436\u0440\u043E\u0439 .</p></div><div class="stanza"><a href="#s8.97-98" id="s8.97-98" class="num">8.97-98</a><p>(\u0412 \u044E\u0433\u043E-\u0432\u043E\u0441\u0442\u043E\u0447\u043D\u043E\u043C \u043B\u0435\u043F\u0435\u0441\u0442\u043A\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C) \u0410\u0433\u043D\u0435\u0438, \u0434\u0435\u0440\u0436\u0430\u0449\u0443\u044E \u0432 \u0440\u0443\u043A\u0430\u0445 \u043A\u043E\u043F\u044C\u0435, (\u0432 \u044E\u0436\u043D\u043E\u043C \u043B\u0435\u043F\u0435\u0441\u0442\u043A\u0435) \u042F\u043C\u0438 \u0434\u0435\u0440\u0436\u0430\u0449\u0443\u044E \u0432 \u0440\u0443\u043A\u0430\u0445 \u043F\u0430\u043B\u043A\u0443. \u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0442\u0430\u043A\u0436\u0435 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u041D\u0430\u0439\u0440\u0438\u0442\u0438, \u0412\u0430\u0440\u0443\u043D\u0438, \u0412\u0430\u044F\u0432\u0438, \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0438\u0445 (\u043E\u0440\u0443\u0436\u0438\u0435\u043C), \u043C\u0435\u0447\u0435\u043C, \u0441\u0438\u043B\u043A\u043E\u043C \u0438 \u0444\u043B\u0430\u0433\u043E\u043C, \u043E \u0412\u043E\u0437\u043B\u044E\u0431\u043B\u0435\u043D\u043D\u0430\u044F! \u0410 \u0442\u0430\u043A\u0436\u0435 \u041A\u0430\u0443\u0431\u0435\u0440\u0438, \u0434\u0435\u0440\u0436\u0430\u0449\u0443\u044E \u0432 \u0440\u0443\u043A\u0430\u0445 \u043C\u043E\u043B\u043E\u0442 \u0438 \u0418\u0448\u0430\u043D\u0438 \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0442\u0440\u0435\u0437\u0443\u0431\u0446\u0435\u043C .</p></div><div class="stanza"><a href="#s8.99" id="s8.99" class="num">8.99</a><p>\u041F\u043E\u0447\u0442\u0438\u0432, \u0438\u0445 \u0431\u043B\u0430\u0433\u043E\u0432\u043E\u043D\u0438\u044F\u043C\u0438, \u0446\u0432\u0435\u0442\u0430\u043C\u0438 \u0438 \u043F\u0440\u043E\u0447\u0438\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0432\u0435\u0440\u0448\u0438\u0442\u044C \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E \u0445\u043E\u043C\u0443. \u0412\u043D\u0430\u0447\u0430\u043B\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0434\u0433\u043E\u0442\u043E\u0432\u0438\u0442\u044C \u043A\u0430\u043B\u0430\u0448\u0443, \u0437\u0430\u0433\u043E\u0432\u043E\u0440\u0435\u043D\u043D\u0443\u044E \u043C\u0430\u043D\u0442\u0440\u0430\u043C\u0438 \u0431\u043E\u043B\u0435\u0435 \u0442\u044B\u0441\u044F\u0447\u0438 \u0440\u0430\u0437 .</p></div><div class="stanza"><a href="#s8.100" id="s8.100" class="num">8.100</a><p>\u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u0445\u043E\u043C\u0443 \u0442\u044B\u0441\u044F\u0447\u0443 \u0440\u0430\u0437, (\u0437\u0430\u0442\u0435\u043C), \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0432 \u0434\u0436\u0430\u043F\u0443, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u043E\u0438\u0437\u0432\u0435\u0441\u0442\u0438 \u0432\u0438\u0441\u0430\u0440\u0434\u0436\u0430\u043D\u0443. \u0412\u044B\u043F\u043E\u043B\u043D\u0438\u0432 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E (\u0434\u0436\u0430\u043F\u0443) \u0441\u0442\u043E \u0432\u043E\u0441\u0435\u043C\u044C \u0440\u0430\u0437, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0438\u0441\u0442\u0443\u043F\u0438\u0442\u044C \u043A \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u044E .</p></div><div class="stanza"><a href="#s8.101" id="s8.101" class="num">8.101</a><p>\u0412 \u043D\u0430\u0447\u0430\u043B\u0435 \u0443\u0441\u0442\u0430\u043D\u0430\u0432\u043B\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0441\u043E\u0441\u0443\u0434 \u0441\u0434\u0435\u043B\u0430\u043D\u043D\u044B\u0439 \u0438\u0437 \u0437\u043E\u043B\u043E\u0442\u0430 \u0438 \u043F\u0440\u043E\u0447\u0435\u0433\u043E, \u0441\u043E \u0432\u0441\u0435\u043C\u0438 \u043C\u0430\u043D\u0442\u0440\u0430\u043C\u0438 \u0446\u0435\u043B\u0435\u0431\u043D\u044B\u043C\u0438 \u0442\u0440\u0430\u0432\u0430\u043C\u0438 \u0432\u043D\u0443\u0442\u0440\u0438, \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u0439 \u0430\u0440\u043E\u043C\u0430\u0442\u043D\u043E\u0439 \u0432\u043E\u0434\u043E\u0439 .</p></div><div class="stanza"><a href="#s8.102" id="s8.102" class="num">8.102</a><p>\u0421 \u0432\u0435\u0442\u043A\u0430\u043C\u0438 \u043C\u0430\u043D\u0433\u043E (\u0440\u0430\u0437\u043C\u0435\u0449\u0435\u043D\u043D\u044B\u043C\u0438) \u0432 \u0433\u043E\u0440\u043B\u044B\u0448\u043A\u0435, \u0441 \u0431\u0435\u043B\u043E\u0439 \u043D\u0438\u0442\u044C\u044E \u043F\u0435\u0440\u0435\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0439 \u043F\u043E \u0433\u043E\u0440\u043B\u044B\u0448\u043A\u0443, \u043E\u0442\u043C\u0435\u0447\u0435\u043D\u043D\u044B\u0439 \u0442\u0438\u043B\u0430\u043A\u043E\u0439 \u0434\u043B\u044F \u0443\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u0437\u043B\u044B\u0445 \u0434\u0443\u0445\u043E\u0432, \u0437\u0430\u0432\u0435\u0440\u043D\u0443\u0442\u044B\u0439 \u0432 \u0434\u0432\u0430 \u043A\u0443\u0441\u043A\u0430 \u0431\u0435\u043B\u043E\u0439 \u0442\u043A\u0430\u043D\u0438 .</p></div><div class="stanza"><a href="#s8.103" id="s8.103" class="num">8.103</a><p>\u041F\u043E\u0447\u0438\u0442\u0430\u0435\u043C\u044B\u0439 \u043C\u0443\u043B\u0430\u043C\u0430\u043D\u0442\u0440\u043E\u0439, \u043F\u043E\u0432\u0442\u043E\u0440\u0435\u043D\u043D\u043E\u0439 \u0441\u0442\u043E \u0432\u043E\u0441\u0435\u043C\u044C \u0440\u0430\u0437. \u0417\u0430\u0442\u0435\u043C \u043E\u043D \u043F\u043E\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F \u0441 \u0430\u0441\u0442\u0440\u0430 \u043C\u0430\u043D\u0442\u0440\u043E\u0439 \u0412\u0430\u0440\u0434\u0445\u0430\u043D\u0438;</p></div><div class="stanza"><a href="#s8.104" id="s8.104" class="num">8.104</a><p>\u041F\u043E\u0434\u043D\u0435\u0441\u0435\u043D\u0438\u0435\u043C \u0441\u0442\u0430\u0440\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0430\u0441\u0430\u043D\u0435 \u043F\u0440\u0438\u0433\u043E\u0440\u0448\u043D\u0435\u0439 (\u043F\u043E\u0434\u043D\u043E\u0448\u0435\u043D\u0438\u0439) \u043A\u0430\u043A \u0431\u044B\u043B\u043E \u043E\u043F\u0438\u0441\u0430\u043D\u043E. \u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0447\u0442\u0438\u0442\u044C \u0418\u043D\u0434\u0440\u0443 \u0438 \u043F\u0440\u043E\u0447\u0438\u0445 (\u0431\u043E\u0433\u043E\u0432, \u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u043D\u044B\u0445) \u043F\u043E \u0441\u0442\u043E\u0440\u043E\u043D\u0430\u043C \u0441\u0432\u0435\u0442\u0430 \u0441 \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0435\u043D\u0438\u0435\u043C \u0433\u043B\u0430\u0441\u043D\u044B\u0445 .</p></div><div class="stanza"><a href="#s8.105" id="s8.105" class="num">8.105</a><p>\u0420\u0430\u0437\u0434\u0435\u043B\u0438\u0432 \u0437\u0435\u043C\u043B\u044E, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0434\u043D\u0435\u0441\u0442\u0438 (\u043F\u043E\u0434\u043D\u043E\u0448\u0435\u043D\u0438\u044F) \u0412\u0430\u0440\u0434\u0445\u0430\u043D\u0438. \u041E\u0431\u0432\u0435\u0434\u044F \u043A\u0430\u043B\u0430\u0448\u0443, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0442\u0438 \u0442\u0430\u043A\u0443\u044E \u043C\u0430\u043D\u0442\u0440\u0443 \u0412\u043B\u0430\u0434\u044B\u043A\u0438 \u043C\u0438\u0440\u0430 (\u0418\u043D\u0434\u0440\u044B):</p></div><div class="stanza"><a href="#s8.106" id="s8.106" class="num">8.106</a><p>\u041E, \u043E, \u0428\u0430\u043A\u0440\u0430, \u0432 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0438 \u0442\u0432\u043E\u0435\u0439 \u043E\u0431\u0438\u0442\u0435\u043B\u0438, \u0440\u0430\u0434\u0438 \u0443\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u043F\u0440\u0435\u043F\u044F\u0442\u0441\u0442\u0432\u0438\u0439 \u0434\u0430 \u0431\u0443\u0434\u0435\u0442 \u0442\u0449\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D \u043E\u0431\u0440\u044F\u0434 \u043F\u043E \u0412\u043E\u043B\u0435 \u0428\u0438\u0432\u044B!</p></div><div class="stanza"><a href="#s8.107" id="s8.107" class="num">8.107</a><p>\u041F\u0435\u0440\u0435\u043D\u0435\u0441\u044F \u0442\u0443\u0434\u0430 \u043F\u0440\u0435\u0436\u0434\u0435 \u0441\u0438\u0434\u0435\u043D\u0438\u0435, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0441\u043E\u0441\u0443\u0434, \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0449\u0438\u0439 \u043C\u0443\u0440\u0442\u0438. \u0421 \u043F\u0440\u0430\u0432\u043E\u0439 (\u044E\u0436\u043D\u043E\u0439) \u0441\u0442\u043E\u0440\u043E\u043D\u044B \u043E\u0442 \u043D\u0435\u0433\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0412\u0430\u0440\u0434\u0445\u0430\u043D\u0438 .</p></div><div class="stanza"><a href="#s8.108" id="s8.108" class="num">8.108</a><p>\u041F\u043E \u043E\u043A\u043E\u043D\u0447\u0430\u043D\u0438\u0438 \u043F\u043E\u0447\u0438\u0442\u0430\u043D\u0438\u044F \u0435\u0433\u043E \u0432 \u043E\u0431\u0440\u0430\u0437\u0435 \u0410\u0442\u043C\u0430\u043D\u0430, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0442\u044C (\u0435\u0435) \u0432 \u0441\u043E\u0441\u0443\u0434\u0435. \u0411\u043B\u0430\u0433\u043E\u0432\u043E\u043D\u0438\u044F\u043C\u0438, \u0446\u0432\u0435\u0442\u0430\u043C\u0438 \u0438 \u043F\u0440\u043E\u0447\u0438\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0437\u0430\u0442\u0435\u043C \u043F\u043E\u0447\u0438\u0442\u0430\u0442\u044C \u0432 \u043D\u0435\u043C \u0412\u0430\u0440\u0434\u0445\u0430\u043D\u0438 .</p></div><div class="stanza"><a href="#s8.109" id="s8.109" class="num">8.109</a><p>\u0421\u0434\u0435\u043B\u0430\u0432 \u0441\u0442\u0430\u0440\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0431\u043B\u0430\u0433\u043E\u0432\u043E\u043D\u0438\u044F\u043C\u0438 \u043C\u0430\u043D\u0434\u0430\u043B\u0443, (\u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0449\u0443\u044E) \u043E\u0431\u043B\u0430\u0441\u0442\u044C \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0430 (\u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0435 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E) \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0447\u0438\u0442\u0430\u0442\u044C \u0428\u0435\u0441\u0442\u0435\u0440\u043A\u0443, \u0422\u0440\u043E\u0439\u043A\u0443 \u0438\u043B\u0438 \u0435\u0434\u0438\u043D\u0438\u0446\u0443 .</p></div><div class="stanza"><a href="#s8.110" id="s8.110" class="num">8.110</a><p>(\u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442) \u0440\u0430\u0441\u0447\u0435\u0440\u0447\u0438\u0432\u0430\u043D\u0438\u0435 \u0436\u0435\u0440\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u044F\u043C\u044B, \u0435\u0435 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435, \u0443\u043C\u0430\u0449\u0435\u043D\u0438\u0435, (\u0437\u0430\u0442\u0435\u043C \u0447\u0435\u0440\u0447\u0435\u043D\u0438\u0435) \u043F\u0435\u0440\u0435\u043A\u0440\u0435\u0441\u0442\u043A\u0430, \u043E\u0433\u0440\u0430\u0436\u0434\u0435\u043D\u0438\u0435, \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0430 \u0432\u0430\u0434\u0436\u0440\u044B .</p></div><div class="stanza"><a href="#s8.111" id="s8.111" class="num">8.111</a><p>(\u0417\u0430\u0442\u0435\u043C) \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442\u0441\u044F \u0432\u044B\u0441\u0442\u0438\u043B\u0430\u043D\u0438\u0435 (\u043E\u0433\u043D\u0435\u043D\u043D\u043E\u0439 \u044F\u043C\u044B) \u0442\u0440\u0430\u0432\u043E\u0439 \u043A\u0443\u0448\u0430 \u0438 \u0440\u0430\u0441\u043A\u043B\u0430\u0434\u043A\u0430 \u0434\u0440\u043E\u0432. \u0412\u0441\u0435 \u044D\u0442\u043E \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442\u0441\u044F \u0441 \u0430\u0441\u0442\u0440\u0430 (\u043C\u0430\u043D\u0442\u0440\u043E\u0439), \u0437\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0434\u043E\u0431\u0430\u0432\u0438\u0442\u044C \u0432\u0438\u0434\u044C\u044F (\u043C\u0430\u043D\u0442\u0440\u0443), \u0438 \u041E\u041C \u0438 \u0425\u0420\u0418\u041C .</p></div><div class="stanza"><a href="#s8.112" id="s8.112" class="num">8.112</a><p>\u0417\u0430\u0442\u0435\u043C, \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u044F \u043F\u043E\u0447\u0438\u0442\u0430\u043D\u0438\u0435, \u0434\u043E\u0431\u0430\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0434\u0432\u0430 (\u0441\u043B\u043E\u0432\u0430) \u0428\u0418\u0412\u0410 \u0438 \u041E\u041C. \u0412 \u0441\u043E\u0441\u0443\u0434 \u0438\u043B\u0438 \u0432 \u0441\u0442\u0440\u0435\u043B\u0443 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0438\u0437\u0432\u0430\u0442\u044C \u0414\u0436\u0430\u0442\u0430\u0432\u0435\u0434\u0430\u0441\u0430 (\u041E\u0433\u043E\u043D\u044C) .</p></div><div class="stanza"><a href="#s8.113" id="s8.113" class="num">8.113</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0428\u0438\u0432\u0443, \u043A\u0430\u043A \u0441\u0435\u043C\u044F, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0435\u0433\u043E \u0432 \u043B\u043E\u043D\u043E \u0412\u0438\u0434\u044C\u0438. \u0417\u0430\u0442\u0435\u043C, (\u0432\u044B\u043F\u043E\u043B\u043D\u044F\u044F) \u043F\u044F\u0442\u044C \u0430\u0445\u0443\u0442\u0438 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u0445\u043E\u043C\u0443 \u0412\u0438\u0434\u044C\u0435, \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0435\u0435 \u0447\u0430\u0441\u0442\u044F\u043C\u0438 \u0442\u0435\u043B\u0430 .</p></div><div class="stanza"><a href="#s8.114" id="s8.114" class="num">8.114</a><p>\u0417\u0430\u0442\u0435\u043C (\u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442\u0441\u044F) \u043E\u0431\u0440\u044F\u0434 \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u0438 \u043F\u0440\u043E\u0447\u0435\u0433\u043E, \u0437\u0430\u0442\u0435\u043C \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u044E\u0442\u0441\u044F \u0432\u0441\u0435 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u044B\u0435 \u043E\u0431\u0440\u044F\u0434\u044B. \u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u043F\u0430\u0440\u0430\u0430\u043F\u0430\u0440\u0430 (\u0432\u0438\u0434\u044C\u044E) \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0434\u043D\u0435\u0441\u0442\u0438 \u043F\u0443\u0440\u043D\u0430\u0445\u0443\u0442\u0438 .</p></div><div class="stanza"><a href="#s8.115" id="s8.115" class="num">8.115</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0447\u0442\u0438\u0442\u044C \u043C\u0430\u0442\u044C \u043E\u0433\u043D\u044F \u0438 \u0435\u0433\u043E \u043E\u0442\u0446\u0430, \u0430 \u0437\u0430\u0442\u0435\u043C \u043E\u0442\u043F\u0443\u0441\u0442\u0438\u0442\u044C. \u0418\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044F \u0432\u043E\u0437\u043B\u0438\u044F\u043D\u0438\u0435 \u043C\u0430\u0441\u043B\u0430, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0437\u0430\u0442\u0435\u043C \u0440\u0430\u0437\u0436\u0435\u0447\u044C \u043E\u0433\u043E\u043D\u044C .</p></div><div class="stanza"><a href="#s8.116" id="s8.116" class="num">8.116</a><p>\u0412\u0431\u0438\u0440\u0430\u044F \u0441 \u0434\u044B\u0445\u0430\u043D\u0438\u0435\u043C \u043E\u0433\u043E\u043D\u044C \u043C\u044B\u0441\u043B\u0435\u043D\u043D\u043E \u0447\u0435\u0440\u0435\u0437 \u043B\u0435\u0432\u0443\u044E (\u043D\u043E\u0437\u0434\u0440\u044E) \u0438 \u0437\u0430\u0434\u0435\u0440\u0436\u0430\u0432 \u0435\u0433\u043E \u0432 \u0441\u0435\u0440\u0434\u0446\u0435, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 (\u0437\u0430\u0442\u0435\u043C) \u0432\u044B\u043F\u0443\u0441\u0442\u0438\u0442\u044C \u0435\u0433\u043E \u0447\u0435\u0440\u0435\u0437 \u043F\u0440\u0430\u0432\u0443\u044E (\u043D\u043E\u0437\u0434\u0440\u044E) .</p></div><div class="stanza"><a href="#s8.118-119" id="s8.118-119" class="num">8.118-119</a><p>\u0417\u0430\u0442\u0435\u043C, \u043A\u0430\u043A \u0438 \u0440\u0430\u043D\u0435\u0435, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0434\u043D\u0435\u0441\u0442\u0438 \u043F\u0443\u0440\u043D\u0430 (\u0430\u0445\u0443\u0442\u0438). \u0422\u0430\u043A\u043E\u0432\u043E \u043D\u0438\u0437\u0448\u0435\u0435 \u043F\u0440\u0430\u0432\u0438\u043B\u043E \u043E\u0433\u043D\u044F \u0428\u0438\u0432\u044B. \u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0415\u0433\u043E, \u043A\u0430\u043A \u0444\u043E\u0440\u043C\u0443 \u0428\u0438\u0432\u044B \u0438 \u0421\u0432\u043E\u0439 \u0410\u0442\u043C\u0430\u043D, \u043F\u0443\u0441\u0442\u044C \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F\u0449\u0438\u0439 \u043C\u0430\u043D\u0442\u0440\u0443 \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442 \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435 (\u043F\u043E\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u0435). \u0412\u044B\u043F\u043E\u043B\u043D\u0438\u0432 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435 \u043F\u043E\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u0435, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0438\u0441\u0442\u0443\u043F\u0438\u0442\u044C \u043A \u0445\u043E\u043C\u0435. \u0412\u044B\u043F\u043E\u043B\u043D\u0438\u0432 \u0441\u0442\u043E \u0440\u0430\u0437 \u0441 \u043C\u0443\u043B\u0430 (\u043C\u0430\u043D\u0442\u0440\u043E\u0439) \u0442\u0430\u0440\u043F\u0430\u043D\u0443 \u0441 \u0435\u0435 \u0447\u0430\u0441\u0442\u044F\u043C\u0438 \u0438 \u0448\u0430\u0434\u0430\u043D\u0433\u0430 (\u043D\u044C\u044F\u0441\u043E\u0439), \u043E\u0441\u0442\u0430\u0432\u0448\u0435\u0439\u0441\u044F \u0434\u0435\u0441\u044F\u0442\u043E\u0439 \u0447\u0430\u0441\u0442\u044C\u044E \u043E\u0442 \u043C\u0430\u043D\u0442\u0440\u044B (\u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442\u0441\u044F) \u0442\u0430\u0440\u043F\u0430\u043D\u0430. \u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0438\u0432\u0435\u0441\u0442\u0438 \u0443\u0447\u0435\u043D\u0438\u043A\u0430, \u0447\u0438\u0441\u0442\u043E\u0433\u043E \u0442\u0435\u043B\u043E\u043C \u0438 \u0441\u044B\u0442\u043E\u0433\u043E .</p></div><div class="stanza"><a href="#s8.120" id="s8.120" class="num">8.120</a><p>\u041F\u043E\u043A\u043B\u043E\u043D\u0438\u0432\u0448\u0438\u0441\u044C, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443, \u0412\u043B\u0430\u0434\u044B\u043A\u0435 \u0431\u043E\u0433\u043E\u0432, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u043C\u0443 \u043D\u0430 \u043F\u0435\u0440\u0435\u043A\u0440\u0435\u0441\u0442\u043A\u0435, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0434\u043D\u0435\u0441\u0442\u0438 \u043F\u0430\u043D\u0447\u0430\u0433\u0430\u0432\u044C\u044E, \u0442\u0435\u043F\u043B\u0435\u043D\u043D\u043E\u0435 \u043C\u0430\u0441\u043B\u043E \u0438 \u043F\u043E\u043B\u043E\u0441\u043A\u0430\u043D\u0438\u0435 \u0434\u043B\u044F \u0437\u0443\u0431\u043E\u0432 .</p></div><div class="stanza"><a href="#s8.121-122" id="s8.121-122" class="num">8.121-122</a><p>\u0421 \u0441\u0435\u043C\u0438\u043A\u0440\u0430\u0442\u043D\u044B\u043C \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0435\u043D\u0438\u0435\u043C \u0445\u0440\u0438\u0434\u0430\u044F \u043C\u0430\u043D\u0442\u0440\u044B, \u043C\u0430\u0441\u043B\u043E\u043C, \u043C\u043E\u043B\u043E\u043A\u043E\u043C \u0438 \u0440\u0438\u0441\u043E\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u0431\u0440\u043E\u0441\u0430\u0442\u044C \u0438\u0445, \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0445 \u043D\u0430 \u0448\u0435\u0441\u0442\u044C \u0447\u0430\u0441\u0442\u0435\u0439 \u0432 \u0440\u0430\u0432\u043D\u044B\u0445 \u043F\u0440\u043E\u043F\u043E\u0440\u0446\u0438\u044F\u0445 \u043C\u0435\u0436\u0434\u0443 \u0431\u043E\u0433\u0430\u043C\u0438, \u043E\u0433\u043D\u0435\u043C, \u0433\u0443\u0440\u0443, \u0443\u0447\u0435\u043D\u0438\u043A\u0430\u043C\u0438, \u0412\u0430\u0440\u0434\u0445\u0430\u043D\u0438 \u0438 \u0441\u043E\u0441\u0443\u0434\u043E\u043C. \u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0434\u043D\u0435\u0441\u0442\u0438 \u0437\u0443\u0431\u043E\u0447\u0438\u0441\u0442\u043A\u0443 \u0441\u0434\u0435\u043B\u0430\u043D\u043D\u0443\u044E \u0438 \u043A\u0448\u0438\u0440\u0430\u0432\u0440\u0438\u043A\u0448\u0438 .</p></div><div class="stanza"><a href="#s8.123" id="s8.123" class="num">8.123</a><p>\u041C\u0435\u0441\u0442\u043E, \u043A\u0443\u0434\u0430 \u043E\u043D\u0430 \u0443\u043F\u0430\u0434\u0435\u0442, (\u0435\u0441\u043B\u0438 \u043E\u043D\u043E) \u043D\u0430 \u0437\u0430\u043F\u0430\u0434\u0435, \u0441\u0435\u0432\u0435\u0440\u0435, \u0441\u0435\u0432\u0435\u0440\u043E-\u0432\u043E\u0441\u0442\u043E\u043A\u0435 \u0438 \u0432\u0432\u0435\u0440\u0445\u0443, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F (\u0431\u043B\u0430\u0433\u043E\u043F\u0440\u0438\u044F\u0442\u043D\u044B\u043C). \u041F\u0440\u043E\u0447\u0438\u0435 - \u043D\u0435\u0431\u043B\u0430\u0433\u043E\u043F\u0440\u0438\u044F\u0442\u043D\u044B, (\u0434\u043B\u044F \u0438\u0445 \u0438\u0441\u043A\u0443\u043F\u043B\u0435\u043D\u0438\u044F) \u0434\u043E\u043B\u0436\u043D\u0430 (\u0431\u044B\u0442\u044C \u0441\u0434\u0435\u043B\u0430\u043D\u0430) \u0432\u043E\u0441\u044C\u043C\u0438\u0441\u043E\u0442\u043A\u0430\u0440\u0442\u043D\u0430\u044F \u0445\u043E\u043C\u0430 .</p></div><div class="stanza"><a href="#s8.124" id="s8.124" class="num">8.124</a><p>\u0417\u0430\u0442\u0435\u043C \u0443\u0447\u0438\u0442\u0435\u043B\u044E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u0432\u043D\u0435\u0448\u043D\u0438\u0439 \u043E\u0431\u0440\u044F\u0434, \u043F\u043E \u0432\u0441\u0435\u043C \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F (\u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F) \u043C\u0430\u043D\u0442\u0440\u0443 \u041E\u041C \u041A\u0428\u0410\u0425 \u041A\u0428\u0410\u0425 \u0421\u0410\u0420\u0412\u0410\u0411\u0425\u0423\u0422\u0415\u0411\u0425\u0419\u0410\u0425 \u0421\u0412\u0410\u0425\u0410 .</p></div><div class="stanza"><a href="#s8.125" id="s8.125" class="num">8.125</a><p>\u0412\u044B\u043F\u043E\u043B\u043D\u0438\u0432 \u0430\u0447\u0430\u043C\u0430\u043D\u0443, \u0441\u043E\u0432\u0435\u0440\u0448\u0438\u0432 \u041D\u044C\u044F\u0441\u0443 \u0438 \u043F\u043E\u0447\u0442\u0438\u0432 \u0428\u0430\u043D\u043A\u0430\u0440\u0443 (<em>\u0442\u0435\u043A\u0441\u0442 \u043F\u043E\u0432\u0440\u0435\u0436\u0434\u0435\u043D</em>) \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0447\u0438\u0441\u0442\u044B\u043C \u0432 \u0434\u043E\u043C\u0435 .</p></div><div class="stanza"><a href="#s8.126" id="s8.126" class="num">8.126</a><p>\u0412\u044B\u043F\u043E\u043B\u043D\u0438\u0432 \u041D\u044C\u044F\u0441\u0443 \u043D\u0430 \u0443\u0447\u0435\u043D\u0438\u043A\u0435 \u0438, \u043E\u0441\u043E\u0431\u0435\u043D\u043D\u043E, \u043D\u0430 \u0441\u0435\u0431\u0435, \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0432 \u043D\u0430 \u0440\u0430\u0441\u0441\u0432\u0435\u0442\u0435 \u0435\u0436\u0435\u0434\u043D\u0435\u0432\u043D\u044B\u0435 \u043E\u0431\u0440\u044F\u0434\u044B \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u044C \u0441\u043D\u044B .</p></div><div class="stanza"><a href="#s8.127-129" id="s8.127-129" class="num">8.127-129</a><p>\u0411\u043B\u0430\u0433\u043E\u0439 \u0441\u043E\u043D \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0441\u0442\u043E\u043B\u043A\u043E\u0432\u0430\u0442\u044C, \u0430 \u043D\u0430 \u043D\u0435\u0431\u043B\u0430\u0433\u043E\u0439 \u0441\u043E\u0432\u0435\u0440\u0448\u0438\u0442\u044C \u0445\u043E\u043C\u0443. \u0415\u0441\u043B\u0438 \u0432\u043E \u0441\u043D\u0435 \u0432\u0438\u0434\u044F\u0442\u0441\u044F \u043F\u043B\u043E\u0434\u044B \u0446\u0432\u0435\u0442\u044B \u0438 \u043F\u0440\u043E\u0447\u0435\u0435, \u0436\u0435\u043D\u0449\u0438\u043D\u044B, \u043E\u0431\u043B\u0430\u0447\u0435\u043D\u043D\u044B\u0435 \u0432 \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u044B\u0435 \u043E\u0434\u0435\u0436\u0434\u044B, \u043F\u0440\u0435\u043E\u0434\u043E\u043B\u0435\u043D\u0438\u0435 \u0431\u0435\u0434\u0441\u0442\u0432\u0438\u0439, \u043D\u0430\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u0432 \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u043E\u043C \u043C\u0435\u0441\u0442\u0435, \u043F\u0438\u0442\u044C\u0435 \u0432\u0438\u043D\u0430, \u043E\u0442\u0441\u0435\u0447\u0435\u043D\u0438\u0435 \u0433\u043E\u043B\u043E\u0432\u044B, \u043E\u0442\u043A\u0430\u0437 \u043E\u0442 \u0432\u043A\u0443\u0448\u0435\u043D\u0438\u044F \u043C\u044F\u0441\u0430, \u0432\u0438\u0434\u0435\u043D\u0438\u0435 \u0431\u043E\u0436\u0435\u0441\u0442\u0432, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0435 (\u0441 \u043D\u0438\u043C\u0438) \u0438 \u0443\u043C\u0430\u0449\u0435\u043D\u0438\u0435 (\u0431\u043E\u0436\u0435\u0441\u0442\u0432), \u0442\u043E (\u0441\u0430\u0434\u0445\u0430\u043A\u0430) \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0436\u0435\u043B\u0430\u043D\u043D\u044B\u0435 \u0441\u0438\u0434\u0434\u0445\u0438 .</p></div><div class="stanza"><a href="#s8.130" id="s8.130" class="num">8.130</a><p>\u041F\u043E\u0434\u043E\u0431\u043D\u043E \u044D\u0442\u0438\u043C \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u044E\u0442\u0441\u044F \u0434\u0443\u0440\u043D\u044B\u0435 \u0441\u043D\u044B. (\u0423\u0432\u0438\u0434\u0435\u0432 \u0432\u043E \u0441\u043D\u0435) \u043F\u0440\u0438\u0433\u043E\u0442\u043E\u0432\u043B\u0435\u043D\u0438\u0435 \u043C\u044F\u0441\u0430 \u0438 \u0435\u0433\u043E \u0432\u043A\u0443\u0448\u0435\u043D\u0438\u0435, \u043F\u0430\u0434\u0435\u043D\u0438\u0435 \u0432 \u044F\u043C\u0443 \u0438 \u043F\u0440\u043E\u0447\u0435\u0435;</p></div><div class="stanza"><a href="#s8.131" id="s8.131" class="num">8.131</a><p>\u041A\u0430\u043A \u0441\u043A\u0430\u0437\u0430\u043D\u043E \u0432 \u0442\u0430\u043D\u0442\u0440\u0430\u0445, \u0441\u043E\u0432\u0435\u0440\u0448\u0438\u0432 \u043D\u0435\u0434\u043E\u0437\u0432\u043E\u043B\u0435\u043D\u043D\u043E\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435, \u043E\u0442 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u0442\u0435\u0440\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435 \u0434\u0432\u0430\u0436\u0434\u044B\u0440\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0433\u043E, \u043C\u0443\u0434\u0440\u043E\u043C\u0443 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0442\u044C \u043F\u043E\u0447\u0438\u0442\u0430\u043D\u0438\u0435 \u0431\u043E\u0433\u043E\u0432, \u043E\u0433\u043D\u044F, \u0433\u0443\u0440\u0443 \u0438 \u0414\u0435\u0432\u0438 .</p></div><div class="stanza"><a href="#s8.132" id="s8.132" class="num">8.132</a><p>\u041D\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u043A\u0443\u0448\u0430\u0442\u044C \u043D\u0438\u0447\u0435\u0433\u043E \u043D\u0435 \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u043D\u043E\u0433\u043E. \u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0438\u0437\u0431\u0435\u0433\u0430\u0442\u044C \u0438\u043C\u0443\u0449\u0435\u0441\u0442\u0432\u0430 \u0411\u043E\u0433\u0430, \u0438\u043C\u0443\u0449\u0435\u0441\u0442\u0432\u0430 \u0433\u0443\u0440\u0443, \u0438\u043C\u0443\u0449\u0435\u0441\u0442\u0432\u0430 \u0414\u0435\u0432\u0438 .</p></div><div class="stanza"><a href="#s8.133" id="s8.133" class="num">8.133</a><p>\u0417\u043D\u0430\u044E\u0449\u0438\u0439 \u043C\u0430\u043D\u0442\u0440\u0443 \u043D\u0435 \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u0435\u0441\u043F\u043E\u043A\u043E\u0438\u0442\u0441\u044F \u043E \u0442\u043E\u043C, (\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043B\u0438 \u043E\u043D\u0430) \u0431\u0435\u0441\u043F\u043B\u043E\u0434\u043D\u043E\u0439 \u0434\u0430\u0436\u0435 \u043E\u0434\u0438\u043D \u0447\u0430\u0441. \u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0431\u044B\u0442\u044C \u0437\u0430\u043D\u044F\u0442\u044B\u043C \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0439 \u0439\u043E\u0433\u0438 \u0438\u043B\u0438 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0439 \u043C\u0430\u043D\u0442\u0440\u044B .</p></div><div class="stanza"><a href="#s8.134-135" id="s8.134-135" class="num">8.134-135</a><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0434\u0430\u0432 \u043C\u0430\u043D\u0442\u0440\u0443 \u0438\u043B\u0438 \u0432\u044B\u0441\u043B\u0443\u0448\u0430\u0432 \u0435\u0435, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u0432\u0438\u0441\u0430\u0440\u0434\u0436\u0430\u043D\u0443. \u0417\u0430\u0442\u0435\u043C (\u0443\u0447\u0438\u0442\u0435\u043B\u044E) \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u043E\u043C\u043E\u0432\u0435\u043D\u0438\u0435 \u0411\u043E\u0433\u0430 \u0431\u043E\u0433\u043E\u0432, \u0443\u0447\u0435\u043D\u0438\u043A\u0430 \u0438\u043B\u0438 \u0441\u0435\u0431\u044F \u0438\u0437 \u0441\u043E\u0441\u0443\u0434\u0430 \u0428\u0438\u0432\u044B \u0443\u0441\u0442\u0440\u0430\u043D\u044F\u044E\u0449\u0435\u0433\u043E \u0432\u0441\u0435 \u0433\u0440\u0435\u0445\u0438. \u0418\u0442\u0430\u043A, \u043E\u0431\u0440\u044F\u0434 \u0441\u0430\u043C\u0430\u0438 \u043F\u043E\u0432\u0435\u0434\u0430\u043D \u0432\u043A\u0440\u0430\u0442\u0446\u0435 .</p></div><p>\u0422\u0430\u043A\u043E\u0432\u0430 \u0432 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \xAB\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0435\xBB \u0432\u043E\u0441\u044C\u043C\u0430\u044F \u0433\u043B\u0430\u0432\u0430.</p>',107),p=[c];function l(v,e,t,m,r,f){return i(),a("div",null,p)}var z=s(n,[["render",l]]);export{h as __pageData,z as default};
